window.TPP_DAILY=window.TPP_DAILY||{};window.TPP_DAILY["schoolage"]={"aug":{"theme":"Welcome to Our Den","weeks":[{"label":"Week 1 — Our New Den","days":[{"day":"Monday","focus":"Home Base Setup","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Command Center Build","d":"Have your child design an after-school station: a bin or shoebox for supplies, a spot for the backpack, a homework zone. Kids who build their own systems actually use them."},{"t":"Family Team Name","d":"Invent a family team name and motto together, then letter it on a sign for the fridge. Naming the crew makes the new school year feel like a shared mission."}]},{"day":"Tuesday","focus":"Our Family Code","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Code of Honor","d":"Draft three to five after-school agreements together — snack first, kind words, screens after homework — and have everyone sign. Kids follow rules they helped write."},{"t":"Secret Handshake","d":"Challenge your child to invent a family handshake with at least four moves, then teach it to everyone. A silly ritual is glue for a new routine."}]},{"day":"Wednesday","focus":"One Big Goal","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Goal Ladder","d":"Ask your child to pick one big goal for the year, then draw a ladder with numbered steps up to it. Circle step one — that is this week's job."},{"t":"Progress Tracker","d":"Help your child make a simple chart to track the goal — a row of ten circles to color in works great. Watching progress add up keeps motivation real."}]},{"day":"Thursday","focus":"ABC & Red","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"ABC Brainstorm Race","d":"Set a timer for three minutes and race to list school-year words starting with A, B, and C — one column each. Older kids can try only two-syllable words."},{"t":"Red Object Museum","d":"Have your child collect ten red things from around the house, sort them by shade from lightest to darkest, and give the family a curator's tour."}]},{"day":"Friday","focus":"Team Celebration","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Backyard Kickoff Games","d":"Let your child invent a first-week field day: three quick events with household stuff, like sock toss or pillow hop. Moving together burns off first-week nerves."},{"t":"Friday Read-Down","d":"Pile blankets, dim the lights, and let everyone read their own book side by side for twenty minutes. Reading for pleasure is the after-school habit worth protecting."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your den, your rules — these little setups make the whole school year smoother.","items":["Post the family code where everyone can see it, and let your child add one new rule this month.","Keep the after-school station stocked on Sundays — pencils, paper, and a snack shelf.","Practice the secret handshake at drop-off. It says you belong here without a word.","Ask one question at dinner: what was the best one minute of your day?"]}},{"label":"Week 2 — New Friends","days":[{"day":"Monday","focus":"All About Me","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Me Poster","d":"Have your child make an All About Me poster — favorites, talents, one surprising fact — to share with new after-school friends. Knowing what to say makes introductions easier."},{"t":"Interview Swap","d":"Your child writes five interview questions, asks you first, then answers the same ones. Good friendships start with good questions, and this is question practice."}]},{"day":"Tuesday","focus":"Friendship Math","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Favorites Survey","d":"Have your child poll family and friends on one question — best pizza topping, best season — then tally the votes and graph the results. Data is friendlier than it sounds."},{"t":"Conversation Cards","d":"Write ten would-you-rather questions on slips of paper and pull one at dinner all week. Kids who practice conversation at home start them more easily at school."}]},{"day":"Wednesday","focus":"Reaching Out","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Pen Pal Letter","d":"Have your child write a real letter to a cousin, grandparent, or old friend — news, questions, a drawing — and mail it. Getting a reply back is pure magic."},{"t":"New Kid Plan","d":"Brainstorm together: what would help a brand-new kid feel welcome at school? Have your child pick one idea to actually try this week and report back."}]},{"day":"Thursday","focus":"Same & Different","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Circle Compare","d":"Draw two overlapping circles and have your child compare themselves with a friend or sibling — differences outside, things in common in the middle. The middle is where friendship starts."},{"t":"Tradition Trade","d":"Have your child share one family tradition with a friend and ask about one of theirs, then report the coolest thing they learned at dinner."}]},{"day":"Friday","focus":"Friend Fun","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Invent a Game","d":"Challenge your child to invent a brand-new active game using only things in one room, write the rules, and teach the family. Teaching a game is leadership in sneakers."},{"t":"Compliment Round","d":"At dinner, everyone gives the person on their left one specific compliment — something they did, not something they own. Specific kindness is a skill worth drilling."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship is a skill — here are small ways to practice it all week.","items":["Hang the Me Poster where guests can see it and let your child present it once.","Keep the conversation cards in a jar on the table for slow dinner nights.","Read together tonight and talk about how a character made a friend.","Help your child learn two new classmates' names this week — names are the first gift we give."]}},{"label":"Week 3 — Rules & Routines","days":[{"day":"Monday","focus":"Real Jobs","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Family Job Chart","d":"Have your child design the family job chart — real responsibilities like feeding the pet, sorting mail, or setting the table — and choose their own two jobs first."},{"t":"Job Application Day","d":"Post a household job opening and have your child apply with a one-minute pitch: why they are the best hire. Interview them seriously, then award the position."}]},{"day":"Tuesday","focus":"Routine Engineering","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Morning Blueprint","d":"Have your child list every step of the morning routine, time each one for a day, and find the slowest step. Then engineer one fix and test it tomorrow."},{"t":"Launch Pad Test","d":"Build a by-the-door launch pad — backpack, shoes, anything signed — and run a timed out-the-door drill. Can the family beat yesterday's time without rushing anyone?"}]},{"day":"Wednesday","focus":"Time Boss","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Schedule Design Studio","d":"Have your child design their own after-school schedule as a poster — blocks for snack, homework, play, reading — with colors and icons they choose. Ownership beats nagging."},{"t":"Estimate & Beat","d":"Before each task tonight, your child estimates how long it will take, then times it. Writing estimate versus actual sharpens the time sense homework depends on."}]},{"day":"Thursday","focus":"Buddy Leadership","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Reading Buddy","d":"Have your child read aloud to a younger sibling, cousin, or a row of stuffed animals — a Bear Phonics reader or any easy book. Reading to someone younger builds confident, fluent readers."},{"t":"Teach One Skill","d":"Your child picks one thing they do well — shoe tying, a card game, a drawing trick — and teaches it to a family member, step by step, with patience."}]},{"day":"Friday","focus":"Routine Check-In","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Chore Relay","d":"Turn Friday tidy-up into a timed relay: each person resets one room, tags the next runner, and the family races the clock together. Routines stick when they are fun."},{"t":"First Family Meeting","d":"Hold a ten-minute family meeting with your child as the chairperson: what worked this week, what needs fixing, one plan for next week. Leadership starts at the kitchen table."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Routines are kindness in disguise — they tell a kid exactly how to succeed.","items":["Let the job chart live for two weeks before changing it — new habits need runway.","Praise the routine, not just the result: you were ready three minutes early today.","Keep buddy-reading books in a basket a younger sibling can reach.","End the family meeting with one thing everyone is looking forward to."]}},{"label":"Week 4 — All About School","days":[{"day":"Monday","focus":"My School Story","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"After-School Journal","d":"Start an after-school journal: your child decorates a notebook and writes the first entry about their school so far — best moment, funniest moment, one wish."},{"t":"Memory Map","d":"Have your child draw a map of their school entirely from memory — classroom, cafeteria, the good water fountain — then check it against reality tomorrow and revise."}]},{"day":"Tuesday","focus":"Welcome Project","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Welcome Kit Plan","d":"Have your child plan a small welcome activity or kit for their after-school group or a new neighbor — a note, a game to share, a tour. Planning for others is leadership practice."},{"t":"Kindness Poster","d":"Your child designs a poster of three ways to be a good classmate and hangs it by the homework spot. Values you can see get used."}]},{"day":"Wednesday","focus":"School Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Backpack Physics","d":"Weigh the backpack with a bathroom scale, then weigh your child with and without it. Figure the difference together and test whether reorganizing makes the load feel lighter."},{"t":"Snack Lab","d":"Set up a blind taste test of three after-school snacks: your child builds a rating scale, collects everyone's scores, and crowns a winner with the data to prove it."}]},{"day":"Thursday","focus":"School Community","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Playground Review","d":"Have your child review their playground or after-care space like a critic: test everything, rate the top three features, and write one improvement idea worth sending to the principal. Critics who suggest fixes become leaders."},{"t":"Route Walk","d":"Walk or trace your route to school together and have your child call out landmarks, then draw the route with labels at home. Knowing the way builds independence."}]},{"day":"Friday","focus":"Month in Review","domains":["Approaches to Learning","Social & Emotional Development"],"opts":[{"t":"Proud Moment Interview","d":"Interview your child about their first month: proudest moment, hardest moment, one goal for September. Write their answers down — these interviews become treasures."},{"t":"Highlight Reel","d":"Have your child pick the month's top three moments and act each out as a slow-motion instant replay, complete with sportscaster commentary. Replaying wins out loud teaches kids to notice their own progress."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One month in — time to notice how far your child has already come.","items":["Keep the after-school journal by the snack spot so writing becomes automatic.","Mail or hand-deliver the thank-you note together — gratitude lands best in person.","Save the proud-moment interview in a folder; repeat it every August.","Read together tonight and let your child pick the book, no questions asked."]}}]},"sep":{"theme":"All About Me & My Family","weeks":[{"label":"Week 1 — This Is Me","days":[{"day":"Monday","focus":"Identity Journal","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"About Me Journal","d":"Have your child start an About Me journal: decorate the cover, then write the first entry — three things I am great at, one thing I am working on."},{"t":"My Name Story","d":"Your child interviews you about their name: who chose it, what it means, who almost got picked instead. Then they write the story in their own words."}]},{"day":"Tuesday","focus":"Goals & Growth","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Two Goals","d":"Have your child set two goals — one for school, one for home — and write the very first step for each. Two is this month's number, and two goals is plenty."},{"t":"Growth Detective","d":"Pull out baby photos and last year's shoes. Your child lists evidence of how they have grown and changed — taller, faster, braver — like a detective building a case."}]},{"day":"Wednesday","focus":"Super S Self","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"S-Word Portrait","d":"Have your child brainstorm S words that describe them — strong, silly, speedy, sincere — then arrange the words into the shape of their own face or initial."},{"t":"Signature Studio","d":"Your child designs their official signature: try three styles, pick a favorite, and practice it. Signing the About Me journal makes it feel like a real document."}]},{"day":"Thursday","focus":"Me, Measured","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Body Math","d":"Measure height, arm span, hand span, and foot length, and record them in the journal. Is your child's arm span really equal to their height? Check the claim."},{"t":"Personal Records","d":"Set personal records: longest standing jump, most hops in thirty seconds, fastest sock-folding. Write each PR down — your child will beg to re-test in a month."}]},{"day":"Friday","focus":"Sharing Myself","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Me Museum","d":"Your child curates five objects that tell their story — a trophy, a shell, a drawing — arranges them like a museum exhibit, and gives the family a guided tour."},{"t":"Autobiography Chapter","d":"Your child writes or records chapter one of their autobiography: earliest memory, life right now, and one dream ahead. Add it to the About Me journal — future chapters will want company."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kids who know their own story stand a little taller — help yours tell it.","items":["Keep the About Me journal out where writing in it takes zero setup.","Post the two goals on the fridge and check step one off together this week.","Read together tonight; afterward, ask which character your child is most like.","Save the personal records list — re-test in October and celebrate the gains."]}},{"label":"Week 2 — My Family","days":[{"day":"Monday","focus":"Family Map","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Family Tree Build","d":"Have your child build a family tree or family map — names, branches, maybe photos — going back as far as you can together. Expect great questions along the way."},{"t":"Grandparent Interview","d":"Your child calls a grandparent or older relative with three prepared questions about their childhood, takes notes, and writes up the best answer as a mini story."}]},{"day":"Tuesday","focus":"Tradition Time","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Recipe Reporter","d":"Cook a family recipe together with your child as the reporter: they measure, they write each step like a real recipe card, and they name the dish's history."},{"t":"Tradition Poster","d":"Have your child pick one family tradition — taco night, the birthday song, the holiday drive — and make a poster explaining it to someone who has never seen it."}]},{"day":"Wednesday","focus":"Family Detective","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Family Traits Lab","d":"Run a traits survey: who in the family has curly hair, can roll their tongue, is left-handed? Your child charts the results and looks for patterns across generations."},{"t":"Where We're From","d":"Mark every place your family has lived on a map your child draws. Talk about one move — why it happened and what it took. Family history is real history."}]},{"day":"Thursday","focus":"Family by Numbers","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Data","d":"Your child gathers family numbers — ages, birthdays, shoe sizes — then finds the totals, the oldest-to-youngest gap, and one surprising fact to announce at dinner."},{"t":"Home Blueprint","d":"Have your child draw a floor plan of your home using squares and rectangles for each room, labeled and roughly to scale. Architects start exactly this way."}]},{"day":"Friday","focus":"Family Fun Night","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Family Talent Show","d":"Everyone performs one talent — jokes, cartwheels, a song — with your child as emcee, making the lineup and introducing each act. Applause for all, always."},{"t":"Generation Games","d":"Teach your child a game you played growing up — hopscotch, jacks, hand-clap games — and play it together for real. Then let them teach you one of theirs."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family stories are the roots kids grow from — dig up a few this week.","items":["Hang the family tree where relatives can add what your child missed.","Add the recipe card to a family cookbook folder — one card a month adds up.","Swap bedtime jobs one night: your child reads aloud to you.","Tell your child one story about yourself at their exact age."]}},{"label":"Week 3 — My Feelings","days":[{"day":"Monday","focus":"Feelings Journal","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Feelings Weather Report","d":"Start a feelings journal: each day your child writes their inner weather — sunny, stormy, foggy — and one sentence about why. Naming a feeling shrinks it to a manageable size."},{"t":"Emotion Color Key","d":"Your child builds a personal color code — maybe orange for energized, blue for calm — then colors today's page to match the day. No words required on hard days."}]},{"day":"Tuesday","focus":"Calm-Down Toolkit","domains":["Approaches to Learning","Physical Development"],"opts":[{"t":"Calm-Down Kit","d":"Have your child build a personal calm-down toolkit in a shoebox: a squeeze ball, headphones, a favorite photo, a note to themselves. They choose what goes in — that is the point."},{"t":"Square Breathing","d":"Teach square breathing: trace a square in the air — breathe in for four, hold four, out four, hold four. Practice when calm so it works when upset."}]},{"day":"Wednesday","focus":"Feelings Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Body Clues Map","d":"Trace a body outline and have your child mark where they feel each feeling — butterflies here, hot cheeks there. Spotting the body's early clues is emotional radar."},{"t":"Calm Stopwatch","d":"Run an experiment: which works faster to settle down — square breathing, ten jumping jacks, or quiet music? Your child times each one and records the results."}]},{"day":"Thursday","focus":"Express It","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Mood Playlist","d":"Your child builds two playlists — one for pumping up, one for cooling down — and tests each with a family dance or stretch. Music is a feelings tool you can carry anywhere."},{"t":"Feelings in Languages","d":"Learn to say happy, sad, and brave in two other languages — ask friends or family who speak them. Feelings are universal; the words for them are a world tour."}]},{"day":"Friday","focus":"Kind Words","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Sticky-Note Kindness","d":"Your child writes small encouraging notes and hides them where family members will find them — a lunchbox, a mirror, a shoe. Kindness you plan still counts double."},{"t":"Feelings Charades","d":"Play feelings charades: act out emotions with your whole body, no words, while the family guesses. Reading faces and body language is a friendship superpower."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Big kids have big feelings too — this week is about tools, not lectures.","items":["Keep the calm-down kit somewhere your child can grab it without asking.","Read Your Feelings Matter together and let your child pick the page that fits their week.","Try square breathing yourself in front of your child — modeling beats explaining.","Ask about the feelings journal only if invited; a journal is theirs first."]}},{"label":"Week 4 — My Friends & Community","days":[{"day":"Monday","focus":"Our Code","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"After-School Code","d":"Have your child write the family's after-school code — how we treat each other, how we handle homework, how we fix mistakes — and present it for signatures like a founding document."},{"t":"Friendship Recipe","d":"Your child writes a recipe for a good friend: two cups of listening, a spoonful of jokes, a pinch of patience. Post it — it is a values statement in disguise."}]},{"day":"Tuesday","focus":"Reading Buddies","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Buddy Read-Aloud","d":"Have your child read aloud to a younger sibling or neighbor — a Bear Phonics reader or any favorite picture book — with voices, pauses, and a question at the end."},{"t":"Book Review Cards","d":"Your child writes short review cards for three books they would recommend — two sentences and a star rating each — and shares the cards with a friend or cousin."}]},{"day":"Wednesday","focus":"Community Study","domains":["Social Studies","Mathematical Thinking"],"opts":[{"t":"Helper Interview","d":"Your child picks a community helper — mail carrier, firefighter, librarian — writes three interview questions, and asks them in person with you alongside, or drafts a thank-you note instead."},{"t":"Neighborhood Tally Walk","d":"Walk the block together while your child tallies what a community needs — stop signs, mailboxes, streetlights — then turns the tallies into a quick chart at home."}]},{"day":"Thursday","focus":"Service Project","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Kindness Experiment","d":"Your child plans three kind acts, predicts how each person will react, does them, and records what actually happened. Kindness plus observation equals a scientist with heart."},{"t":"Give-Away Sort","d":"Have your child sort outgrown books and toys into keep, donate, and pass-to-a-friend piles, then help deliver the donations. Letting go is easier with a mission."}]},{"day":"Friday","focus":"Celebrate Us","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Game Night Director","d":"Your child runs family game night start to finish: picks the games, explains the rules, keeps score, and settles disputes fairly. Running the room is real leadership."},{"t":"Gratitude Garland","d":"Everyone writes people they are thankful for on paper squares, and your child strings them into a garland for the kitchen. Add squares all fall as the list grows."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week your child practices being someone a community can count on.","items":["Frame or fridge-post the signed after-school code — official documents deserve display.","Set a weekly buddy-reading time so the little ones start expecting it.","Deliver the donations together and let your child hand them over.","At dinner, ask: who did you help today, and who helped you?"]}}]},"oct":{"theme":"The Great Outdoors","weeks":[{"label":"Week 1 — Leaves & Trees","days":[{"day":"Monday","focus":"Field Guide Start","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Leaf Field Guide","d":"Have your child collect five different leaves, tape each into a homemade field guide, and label what they notice — edges, veins, size. Real naturalists start with real notebooks."},{"t":"Adopt a Tree","d":"Your child picks one nearby tree to adopt for the month: name it, sketch it, and write the first journal entry. Watching one tree change is a whole science course."}]},{"day":"Tuesday","focus":"Tree Math","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Leaf Sort & Graph","d":"Sort the leaf collection by size, shape, or color, then graph the piles. Ask which shapes show up most — triangles, ovals, hearts — and hunt for a reason why."},{"t":"How Tall Test","d":"Estimate a tree's height, then test it: have your child compare the tree's shadow to their own shadow and do the math. Estimating and checking is thinking like an engineer."}]},{"day":"Wednesday","focus":"Leaf Art","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Rubbing Gallery","d":"Make crayon leaf rubbings — browns, reds, oranges — and let your child arrange the best ones into a framed gallery wall for the hallway. Curating is a skill too."},{"t":"Land Art Design","d":"Outside, your child arranges leaves, sticks, and acorns into a pattern or picture on the ground, then photographs it before the wind takes it. Temporary art teaches bold choices."}]},{"day":"Thursday","focus":"Tree Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"T-Word Wall","d":"Start a T word wall from a walk outside — trunk, twig, towering, tumble. Challenge your child to add three new T words a day through Friday."},{"t":"Trees & Us","d":"Have your child list every way trees help people — shade, paper, fruit, homes for animals — then rank the top three and defend their picks at dinner."}]},{"day":"Friday","focus":"Under the Tree","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Reading Picnic","d":"Take blankets and books outside and read under a tree together — everyone with their own book, shoulder to shoulder. Fresh-air reading turns a habit into a memory."},{"t":"Leaf Pile Games","d":"Rake a pile together, then let the jumping begin — plus leaf-toss contests and a race to refill the pile. The raking is the workout; the jumping is the paycheck."}]}],"homeden":{"title":"The Home Den — This Week","lead":"October is the easiest month to get outside — the trees are doing the teaching.","items":["Keep the leaf field guide by the door so every walk can add a page.","Visit the adopted tree weekly and date each sketch — the changes will amaze you both.","Press the best leaves inside a heavy book for a keepsake later.","Trade screens for one after-dinner walk this week and count the brown things you pass."]}},{"label":"Week 2 — Bugs & Critters","days":[{"day":"Monday","focus":"Bug Watching","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Bug-Watch Journal","d":"Have your child sit quietly near a bush or sidewalk crack for ten minutes and sketch every critter that passes, with notes on what it was doing. Stillness is a science skill."},{"t":"Critter Count","d":"Set a timer for fifteen minutes outside and tally every ant, beetle, bee, and butterfly by type. Which critter won? Try the same count at a different time tomorrow and compare."}]},{"day":"Tuesday","focus":"Insect Expert","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Three-Fact Card","d":"Your child picks a favorite insect, finds three true facts in a book or with your help online, and makes an expert card with a drawing. Three facts, this month's number, makes an expert."},{"t":"Build a Bug","d":"Using recycling-bin materials, your child builds a model insect the right way: three body parts, six legs, two antennae. Getting the anatomy right is the whole challenge."}]},{"day":"Wednesday","focus":"Critter Homes","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Spider Web Study","d":"Find a spider web early in the morning and have your child sketch its design — look for the triangles between the spokes. Never touch; the architect is probably home."},{"t":"Bug Hotel Build","d":"Stuff a small box with twigs, pinecones, bark, and rolled cardboard to make a bug hotel, then place it outside and check for guests every day this week."}]},{"day":"Thursday","focus":"G & J Critters","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"G-J Critter List","d":"Challenge your child to list critters starting with G or J — grasshopper, gecko, june bug, jellyfish — then sort the list into ones you could actually spot in Florida."},{"t":"Insect Athletics","d":"Run insect field events: measure a standing grasshopper jump, time a beetle-crawl dash, and see who holds a praying-mantis balance longest. Record every result — for their size, insects hold the world's wildest records."}]},{"day":"Friday","focus":"Bug Ambassador","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Teach the Littles","d":"Have your child teach a younger sibling or neighbor their three insect facts, show off the bug hotel, and answer questions like a park ranger. Teaching cements learning."},{"t":"Helper or Pest","d":"Together, sort familiar critters into helpers and pests — bees pollinate, mosquitoes bite — and talk about why even the annoying ones have jobs in the neighborhood."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every sidewalk crack is a safari this week — bring the journal.","items":["Keep a magnifier or phone camera handy for close-up bug looks — observe, never squish.","Check the bug hotel each afternoon and log any guests in the journal.","Read a bug book together and compare it to what your child actually saw.","Firefly rule for evening walks: watch, admire, and let them blink away free."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Station","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Rain Gauge Build","d":"Tape a ruler to a straight-sided jar and set it outside in the open — that is a real rain gauge. Your child checks and records it daily this week."},{"t":"Weather Station Corner","d":"Have your child set up a weather chart with a row for each day: temperature, sky, wind, rain. A week of honest data beats a month of guessing."}]},{"day":"Tuesday","focus":"Clouds & Wind","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Cloud Journal","d":"Lie on a blanket and have your child sketch the clouds, then match them to types — puffy cumulus, wispy cirrus, gray blanket stratus. Sky watching is patience training."},{"t":"Wind Sock Maker","d":"Make a wind sock from a paper cup or sleeve and ribbon strips, hang it outside, and invent a family scale: still, breezy, flappy, wild. Rate the wind daily."}]},{"day":"Wednesday","focus":"Weather Reporter","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Data Day","d":"Have your child record the temperature three times today — morning, after school, evening — then graph the curve and explain when the warmest point hit and why."},{"t":"Forecast Anchor","d":"Your child studies today's data and delivers tomorrow's forecast like a TV meteorologist — map, pointer, confident voice. Check the accuracy tomorrow and score it."}]},{"day":"Thursday","focus":"Sky Tricks","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Storm Story","d":"Have your child write a paragraph describing a storm using all five senses — the smell before rain, the sound of the first drops. Weather writing makes strong writers."},{"t":"Shadow Tag & Trace","d":"Play shadow tag, then chalk-trace your child's shadow in the morning and again after school in the same spot. Where did it move? Let them puzzle out why."}]},{"day":"Friday","focus":"Night Sky","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Family Star Watch","d":"Take blankets out after dark and find three star pictures — connect stars into triangles and name your own constellations. Ten quiet minutes under the sky resets a whole week."},{"t":"Weather Around the World","d":"Read together about a place with wildly different weather — desert, tundra, rainforest — and have your child list how kids there dress, play, and get to school."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your junior meteorologist is on duty — check the family forecast before you grab a jacket.","items":["Let your child brief the family each morning from their own weather chart.","Empty the rain gauge after each reading so the next number is honest.","Keep the cloud journal in the car for waiting-in-line sky checks.","Compare Friday's totals to the news forecast and celebrate every hit."]}},{"label":"Week 4 — Animals & Their Homes","days":[{"day":"Monday","focus":"Feeder & Habitats","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Bird Feeder Build","d":"Build a simple bird feeder — a pinecone or cardboard tube rolled in sunflower-seed butter and pressed with birdseed or crushed cereal — and hang it where you can watch from a window."},{"t":"Habitat Survey Walk","d":"Walk the neighborhood and have your child list every animal home they spot — nests, burrows, webs, anthills — and mark each one on a hand-drawn block map."}]},{"day":"Tuesday","focus":"Animal Architects","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Shelter Designer","d":"Your child picks an animal and designs it a dream home — sketch first, then build a model from boxes and tape. The design must solve a real problem: rain, cold, or predators."},{"t":"Nest Engineering","d":"Challenge your child to build a nest using only found materials — twigs, grass, mud — that can cradle a ball egg without dropping it. New respect for birds guaranteed."}]},{"day":"Wednesday","focus":"Backyard Naturalist","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Feeder Watch Log","d":"Have your child track the feeder for two days: tally each visitor by type, note peak snack hour, and report which bird is the boss of the feeder."},{"t":"Camouflage Test","d":"Cut paper moths in brown, gray, and bright colors and scatter them in the yard. Which are hardest for the family to find? That is camouflage doing its job."}]},{"day":"Thursday","focus":"Cozy Dens","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Animal Home Report","d":"Your child writes a mini report or poster on one animal's home — who builds it, what it is made of, one amazing fact — and presents it before dinner."},{"t":"Blanket Den Read-In","d":"Build a blanket-fort den together, stock it with pillows and books, and read inside like bears settling in for winter. Everyone shares their best animal fact at the end."}]},{"day":"Friday","focus":"Nature Leader","domains":["Social Studies","Physical Development"],"opts":[{"t":"Nature Buddy Tour","d":"Have your child lead a younger sibling, cousin, or grown-up on a guided nature tour of the yard or park — feeder, bug hotel, adopted tree — pointing out finds like a ranger."},{"t":"Triangle Trail Map","d":"Your child maps the yard or park with a symbol key — triangles for trees, circles for animal homes — then hides a small prize and lets the family navigate to it."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every creature needs a safe den — this week your child studies how the pros build theirs.","items":["Refill the bird feeder together on weekends and keep the visitor log going into November.","Use sunflower-seed butter for feeders so allergy worries stay off the menu.","Leave the blanket den up through the weekend as the official reading spot.","Save the trail map and nature journal in a folder — a whole month of field work worth keeping."]}}]},"nov":{"theme":"Thankful Hearts","weeks":[{"label":"Week 1 — I Am Thankful","days":[{"day":"Monday","focus":"Launch the Journal","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Gratitude Journal Setup","d":"Fold paper into a booklet or claim a spare notebook, design a cover, and write three things you're thankful for tonight. Kids who name good things regularly carry a steadier, sunnier mood — and this journal runs all month."},{"t":"Gratitude Photo Walk","d":"Walk the house or yard and photograph or sketch five things you're glad you have. Choosing what makes the list is the real thinking — ask why each one earned its spot."}]},{"day":"Tuesday","focus":"Thankful Wall","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Sticky-Note Wall","d":"Start a family thankful wall on the fridge or a door — one sticky note or paper scrap per idea, added daily. Watching the wall fill up all month makes gratitude visible and kind of addictive."},{"t":"Alphabet of Thanks","d":"Challenge yourself to list something you're thankful for from A to Z, then highlight this month's letters H, K, and L in yellow. Tricky letters like Q build the best stick-with-it muscles."}]},{"day":"Wednesday","focus":"Notice and Measure","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Gratitude Tally Chart","d":"Sort your journal entries into four categories — people, places, things, surprises — and tally which one wins. Turning feelings into data is real math, and the results usually surprise everyone."},{"t":"Five-Senses Sit Spot","d":"Sit outside for five quiet minutes and record one thing each sense catches — sounds, smells, sights, textures, even the taste of the air. Scientists call this observation; it also happens to be calming."}]},{"day":"Thursday","focus":"Thanks in Motion","domains":["Physical Development","Social Studies"],"opts":[{"t":"Gratitude Walkabout","d":"Take a brisk walk or bike ride and name one thing you're thankful for at every corner or driveway. Moving bodies loosen up thinking — the best answers show up around block three."},{"t":"Community Helper Map","d":"Sketch a map of your neighborhood and mark the places where people help you — the fire station, the library, a kind neighbor's house. Maps help kids see they belong to a bigger community."}]},{"day":"Friday","focus":"Read and Reflect","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Read Then Reflect","d":"Read for pleasure for twenty minutes — any book counts — then add a journal line about what your character might be thankful for. If big feelings come up, Mrs. Bear's Your Feelings Matter makes a sweet companion read."},{"t":"Thankful Acrostic Poem","d":"Write the word THANKFUL down the page and build a line from each letter, then decorate the page with yellow accents. Poems give big feelings a small, sturdy container."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pop these on the fridge — small gratitude habits that stick all month.","items":["A journal prompt card: keep one line a night going all November.","Sticky notes for the family thankful wall — everyone adds one at dinner.","The H, K, L challenge: spot all three letters on signs, labels, and cereal boxes.","Tonight's table question: what is one good thing that happened today?"]}},{"label":"Week 2 — Family & Home","days":[{"day":"Monday","focus":"Family Story Hunt","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Heirloom Detective","d":"Pick an old family photo or object and detective out its story — ask its owner where it came from, who is in it, and why it was kept. Take notes like a reporter; objects unlock stories that questions alone miss."},{"t":"Recipe Detective Work","d":"Ask a parent or grandparent about a recipe your family always makes. Who taught it to them? Write the story on a card next to the ingredients so it never gets lost."}]},{"day":"Tuesday","focus":"Cook the Story","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Recipe Chef","d":"Help cook the family recipe you researched — you handle the measuring, doubling, or halving. Kitchen math is fractions with a delicious answer at the end."},{"t":"Family Restaurant Night","d":"Turn dinner into a restaurant: design a menu, set prices, take orders on a notepad, and total each bill. Running the whole system from start to finish is the fun part."}]},{"day":"Wednesday","focus":"Where We Come From","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Family Crest Design","d":"Design a family crest: one symbol for each person's superpower, a border in this month's yellow, and four words your family lives by. Seeing the whole crew on one shield helps kids feel rooted in something big."},{"t":"Photo Caption Curator","d":"Choose six family photos and write a caption for each like a museum label — who, where, and why it matters. Curating is deciding what deserves to be remembered."}]},{"day":"Thursday","focus":"Old-School Play","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Old-School Recess","d":"Ask a grown-up to teach you a game from their childhood — hopscotch, jacks, four square — and play a few real rounds together. Games are family heirlooms you can run around in."},{"t":"Simple Machine Hunt","d":"Hunt through the house for four simple machines at work — a doorknob wheel, scissor levers, a ramp, a screw. Home runs on hidden physics; finding it is the fun."}]},{"day":"Friday","focus":"Pass It Down","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Read-Aloud Leader","d":"Be the big kid: read a favorite book aloud to a younger sibling, cousin, or neighbor — a Bear Phonics reader like He Eats Meat is perfect. Teaching a little one is leadership in its coziest form."},{"t":"Tradition Journal Entry","d":"Write about one family tradition you hope to keep when you're grown — describe it so clearly a stranger could picture it. Then read your entry aloud at dinner."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week is all about your family's own story — no supplies needed, just each other.","items":["Three interview questions to ask the oldest relative you can reach this week.","A recipe card: write down one family dish and the story behind it.","A family tree starter — add a leaf per person at dinner each night.","The read-aloud challenge: your big kid reads to a younger one before bed."]}},{"label":"Week 3 — Sharing & Giving","days":[{"day":"Monday","focus":"Plan the Project","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Giving Project Plan","d":"Choose a giving project you can lead this week — a toy donation, cards for helpers, canned goods — and write a real plan with four numbered steps. Kids who plan their own projects own them."},{"t":"Charity Detective","d":"With a grown-up alongside, look up a local food bank or shelter and find out what they actually need most right now. Good givers do their homework first."}]},{"day":"Tuesday","focus":"Sort and Count","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Donation Box Audit","d":"Sort your toys and clothes into keep, donate, and recycle piles, then count and record each donate stack. Letting go of good things for someone else is a big-kid kind of brave."},{"t":"Giving Jar Count","d":"Hunt down the household's stray coins, sort them into groups of four, and count up a giving jar total. Decide together where the money should go — the deciding is the lesson."}]},{"day":"Wednesday","focus":"Kindness on Paper","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Kindness Coupon Book","d":"Make a coupon book of favors you'll really honor — one free dish night, ten minutes of reading to a sibling, a car cleanup — and gift it to someone. Handmade promises beat store-bought anything."},{"t":"Uplift Letter","d":"Write an encouraging letter to someone having a tough stretch — a classmate, a relative, a neighbor. Two honest sentences from a kid can carry a grown-up for a week."}]},{"day":"Thursday","focus":"Helping Hands","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Yard Help Mission","d":"Rake, sweep, or tidy a yard for a family member or neighbor, with a grown-up along. While you work, talk about why trees drop their leaves in fall — service and science in one sweaty hour."},{"t":"Grow to Give","d":"Plant herb or flower seeds in a cup on a sunny windowsill, label it, and tend it to give away later. Track what changes each day — patience with a payoff."}]},{"day":"Friday","focus":"Secret Kindness","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Mystery Gratitude Notes","d":"Write unsigned notes naming exactly what each family member does that you're grateful for, and hide them where they'll be found. At dinner, let everyone guess the author. Gratitude with no credit is the strongest kind."},{"t":"Giving Story Night","d":"Read a book about generosity together — Thank You, Omu! is a favorite — then talk about a time someone shared with you when it really counted."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your kid is running a giving project this week — here's how the family backs them up.","items":["A donation sort checklist: keep, donate, recycle — kid counts the totals.","A kindness coupon template — handmade favors make the best gifts.","Mystery gratitude notes: unsigned, specific, hidden where they'll be found.","A giving jar for stray coins — the family votes where it goes."]}},{"label":"Week 4 — A Thankful Feast","days":[{"day":"Monday","focus":"Thank the Helpers","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Thank-You Note Blitz","d":"Write real thank-you notes to the school helpers nobody remembers to thank — the crossing guard, the cafeteria crew, the bus driver, the custodian. Name the exact thing they do that helps you."},{"t":"One-Minute Toast","d":"Write and rehearse a one-minute gratitude toast to deliver at this week's family feast. A good toast has three parts: a thank-you, a story, and a wish."}]},{"day":"Tuesday","focus":"Feast by Numbers","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Feast Planning Math","d":"Plan the family feast like an event manager: count the guests, figure servings per dish, and sketch a rectangle table map showing who sits where. Real events run on this exact math."},{"t":"Placemat Design Studio","d":"Cut paper rectangles into placemats and design one for each guest with their name and something you appreciate about them. Personalized seats make everyone feel expected."}]},{"day":"Wednesday","focus":"Kitchen Crew","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Feast Prep Crew","d":"Take a real kitchen job — washing, measuring, mixing, kneading — with a grown-up running the stove and the sharp tools, and watch what heat does to your dish. Ask why bread rises or onions turn clear; cooking is chemistry you can eat."},{"t":"Table Setting Boss","d":"Lead the table setup start to finish: carry, arrange, fold napkins, place name cards. Count settings in groups of four to check your work. Being trusted with the whole job is the point."}]},{"day":"Thursday","focus":"Around the Table","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Family Toast Night","d":"At dinner, everyone shares one toast — kids go first, and yours is already rehearsed. Speaking gratitude out loud in front of people you love is a skill that lasts a lifetime."},{"t":"Journal Read-Back","d":"Read back through your gratitude journal from week one and pick three favorite entries to read aloud at the table. A month of small thanks adds up to something surprisingly big."}]},{"day":"Friday","focus":"Close the Month","domains":["Approaches to Learning","Language & Literacy"],"opts":[{"t":"Thankful Time Capsule","d":"Write a letter to next-November you: what you're thankful for now, what you hope changes, one prediction. Seal it, label it, and hide it somewhere you'll actually find it in a year."},{"t":"Book and Blanket Dessert","d":"End the feast week with a reading picnic — blankets on the floor, everyone with a book, twenty quiet minutes together. Reading side by side counts as together time too."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Feast week — put your school-ager in charge and watch them rise to it.","items":["A thank-you note kit: three notes to school helpers, delivered this week.","The feast job chart — every kid owns one real job, start to finish.","A toast starter card: a thank-you, a story, and a wish.","The time-capsule prompt: a sealed letter to open next November."]}}]},"dec":{"theme":"Lights & Traditions Around the World","weeks":[{"label":"Week 1 — Lights Around the World","days":[{"day":"Monday","focus":"Pick Your Festival","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Festival Research Launch","d":"Pick a light celebration from somewhere in the world — Hanukkah, Kwanzaa, St. Lucia Day, Lunar New Year lanterns — and start researching it with books or a grown-up-supervised search. You're the expert on this one all week."},{"t":"World Map Pins","d":"Find or sketch a world map and mark every winter light celebration you can discover, with a line to its country. Watching the marks spread across every continent is the whole lesson."}]},{"day":"Tuesday","focus":"Build the Fact File","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Festival Fact File","d":"Make an official fact card for your festival: name, country, foods, what gets lit, and one wow fact. Bonus challenge: work this month's letters W, F, N, and O into your headings."},{"t":"Interview an Elder","d":"Ask a grandparent or older neighbor what lights and celebrations looked like when they were your age. Write down their best memory word for word — quotes are treasure."}]},{"day":"Wednesday","focus":"The Science of Light","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Shadow Lab","d":"Grab a flashlight in a dark room and experiment: what makes shadows grow, shrink, sharpen, or blur? Record your findings like a scientist — a guess, a test, a result."},{"t":"Sunset Tracker","d":"Look up or watch tonight's sunset time and log it every day this week. The days are getting shorter — chart by how many minutes, and talk about why so many winter festivals celebrate light."}]},{"day":"Thursday","focus":"Make It Glow","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Paper Lantern Build","d":"Fold, cut, and tape a paper lantern like the ones in lantern festivals — cuffs, careful cuts, a handle. Precision hand work like this is a maker skill worth practicing."},{"t":"Evening Light Walk","d":"Take an after-dinner walk around the block and count the lights you spot — windows, porches, strings, stars. Sort your count into categories when you get home."}]},{"day":"Friday","focus":"Teach What You Learned","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Festival Show-and-Teach","d":"Present your festival to the family at dinner — teach three facts, show your lantern or fact card, and take questions. Standing up and teaching what you know builds confidence nothing else can."},{"t":"Flashlight Read-In","d":"Turn off the big lights and read for twenty minutes by flashlight or lamplight — solo or shoulder to shoulder with someone. Low light makes ordinary reading feel like an event."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your school-ager is researching a light festival from around the world — here's how to join in.","items":["The dinner question: which country's light celebration would you visit, and why?","A sunset log — jot tonight's sunset time and watch the days shrink.","A W, F, N, O letter hunt on holiday cards, boxes, and signs.","Friday flashlight reading: twenty minutes, lights low, everyone with a book."]}},{"label":"Week 2 — Family Traditions","days":[{"day":"Monday","focus":"Tradition Inventory","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Tradition Inventory List","d":"List every tradition your family keeps — foods, songs, sayings, the way you always do that one thing. Then interview a parent about traditions from their own childhood and add those too."},{"t":"Tradition Time Machine","d":"Pick one family tradition and trace it backward like a detective: who started it, where, and how it changed. Write its origin story in your own words."}]},{"day":"Tuesday","focus":"Plan the Presentation","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Presentation Storyboard","d":"Plan a family-tradition presentation for Friday: poster, slideshow, or skit — your choice. Storyboard it in five boxes so you know exactly what comes first, next, and last."},{"t":"Prop and Photo Gathering","d":"Collect the props and photos that tell your tradition's story — the recipe card, the ornament, the picture from before you were born. Real objects make a presentation unforgettable."}]},{"day":"Wednesday","focus":"Traditions by Numbers","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Family Tradition Survey","d":"Survey everyone in the family: which tradition is your favorite? Tally the votes, graph the results in groups of five, and announce the winner at dinner like a news anchor."},{"t":"Tradition Timeline","d":"Build a timeline of your family's traditions: when each one started, who started it, and how old it is now. Do the math — is any tradition older than your grandparents? Numbers make family history feel real."}]},{"day":"Thursday","focus":"Rehearse and Refine","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Dress Rehearsal Run","d":"Rehearse your presentation out loud, standing up, with big gestures and a strong ending — time it and run it twice. Every performer knows the second run is always braver."},{"t":"Thirty-Second Trailer","d":"Act out a movie-style trailer for your family tradition — dramatic voice, action scenes, a cliffhanger. Hamming it up today makes the real presentation feel easy tomorrow."}]},{"day":"Friday","focus":"Premiere Night","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Family Premiere Night","d":"Deliver your tradition presentation after dinner — props out, audience seated, questions welcome. Finishing a project you planned, built, and performed all by yourself is a feeling worth collecting."},{"t":"Story Swap Night","d":"Trade stories around the room: grown-ups tell a favorite childhood memory, and kids read a favorite story aloud in return. Reading to your family counts double in December."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week your kid turns a family tradition into a real presentation — be their audience.","items":["Three interview questions about the traditions you grew up with.","A five-box storyboard for planning Friday's presentation.","The prop hunt: find one object that tells your tradition's story.","Friday premiere night — chairs in a row, phones down, applause loud."]}},{"label":"Week 3 — Giving & Kindness","days":[{"day":"Monday","focus":"Drive Headquarters","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Kindness Drive HQ","d":"Organize a small giving drive you can actually run — canned food, gently used books, warm socks. Write a five-step plan: what, who it helps, where it goes, when, and your job."},{"t":"Wish List Research","d":"With a grown-up beside you, look up a local shelter or food pantry and find its real wish list. Givers who do their homework give what people actually need."}]},{"day":"Tuesday","focus":"Spread the Word","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Drive Poster Studio","d":"Design posters for your drive with bold headline letters, green accents, and stars — say what, where, and when in words a hurried grown-up can read in three seconds."},{"t":"Countdown Tracker","d":"Make a five-day countdown calendar for your drive with a goal written at the top. Marking off each day keeps the whole family on mission until the finish."}]},{"day":"Wednesday","focus":"Count and Test","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Collection Count-Up","d":"Count and sort everything your drive has collected so far — tally in groups of five and chart which category is winning. Every real charity tracks its numbers exactly like this."},{"t":"Warmest Fabric Test","d":"Wrap jars of warm water in different fabrics — cotton, fleece, wool — and test which stays warmest longest. Now you know why warm-clothing drives ask for what they ask for."}]},{"day":"Thursday","focus":"Muscle for Good","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Delivery Day Prep","d":"Box, label, carry, and load your drive donations — real lifting, careful stacking, teamwork. Feeling the weight of what you collected is the best part of giving."},{"t":"Helping Hands Circuit","d":"Run a three-stop helping circuit at home: carry in groceries, take out the bins, sweep a porch. Do it fast, do it cheerful, and notice how good tired-from-helping feels."}]},{"day":"Friday","focus":"Reflect and Thank","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Giver's Journal Page","d":"Write a journal page about the drive: the hardest part, the best moment, and one thing you'd do differently next time. Then write thank-you notes to everyone who donated."},{"t":"Kindness Read-Aloud","d":"Read a giving-themed story aloud to a younger kid — a Bear Phonics reader like We See Feet works beautifully. Big kids reading to little ones is kindness and leadership in one."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your school-ager is running a giving drive this week — donate loudly and help quietly.","items":["The five-step drive plan: what, who, where, when, and my job.","A poster-making kit: bold letters, green paper, star shapes.","The count-up chart — tally donations in groups of five each night.","Thank-you notes for every single person who gave."]}},{"label":"Week 4 — Celebrations","days":[{"day":"Monday","focus":"Celebration Committee","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Celebration Committee Meeting","d":"Plan a family celebration that honors more than one tradition — borrow a food, a song, or a custom from a culture you studied this month. Assign every person a real job and write the plan down."},{"t":"Invitation Design Desk","d":"Make an invitation for each family member with the date, time, and a star on the front. A celebration people are personally invited to feels twice as special."}]},{"day":"Tuesday","focus":"Party Math","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Fair Share Math","d":"Count out the party treats and divide them evenly among the guests — then decide what's fair when there's a remainder: split them, save them, or invent a tiebreaker game. Division with leftovers is where math gets real."},{"t":"World Playlist DJ","d":"Build a celebration playlist with songs from at least three different cultures, then add up the minutes so it fits the party. DJs are secretly doing math the whole time."}]},{"day":"Wednesday","focus":"Makerspace Day","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Glow Centerpiece Build","d":"Engineer a table centerpiece that glows safely — a flashlight under colored paper, a jar wrapped in tissue. Test three designs and keep the one that glows best."},{"t":"Star Garland Assembly","d":"Measure, cut, and string a garland of green paper stars long enough to cross the whole room. Measuring, folding, and precise cutting is maker training in disguise."}]},{"day":"Thursday","focus":"Stories of Celebration","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Celebration Story Time","d":"Read a story about a winter celebration different from your own — The Shortest Day is a lovely pick — and talk about what feels familiar and what feels brand new."},{"t":"Celebration Program Writer","d":"Write and design the official program for tomorrow's celebration: order of events, who leads each part, and one welcome line honoring every tradition on the list. A host with a program is a host in charge."}]},{"day":"Friday","focus":"Celebration Night","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Host the Celebration","d":"Tonight the kids run the show — greet guests, start the playlist, serve snacks, run the program. Hosting a celebration you planned yourself is the month's proudest moment."},{"t":"Month of Light Journal","d":"After the party, write a closing journal page: the festival you studied, the tradition you presented, the drive you ran, the celebration you hosted. That was a big month — say so."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Celebration week — hand your kids the clipboard and let them host.","items":["The celebration plan: every family member gets one real job.","A star garland kit — green paper, scissors, string, a measuring tape.","The party program: order of events, one real job per person, written by your kid.","The dinner question: what tradition from another culture would you borrow forever?"]}}]},"jan":{"theme":"Winter Wonders","weeks":[{"label":"Week 1 — Snow & Ice","days":[{"day":"Monday","focus":"Melt the Ice","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Melt Race Lab","d":"Freeze a tray of ice cubes, then race three against each other: one with salt, one with sugar, one plain. Predict the winner first, time the melt, and record what really happened."},{"t":"Ice Rescue Mission","d":"Freeze a few small toys in a cup of water overnight, then engineer a rescue using warm water, salt, and a spoon — no smashing allowed. Constraints are what make engineers clever."}]},{"day":"Tuesday","focus":"Six-Sided Science","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Snowflake Symmetry Fold","d":"Every real snowflake has exactly six sides — this month's number. Fold paper into sixths, cut a snowflake, and check your six-way symmetry when it opens. Tricky folds are the fun part."},{"t":"Crystal Diamond Designs","d":"Look at close-up photos of frost and ice crystals, then draw your own crystal patterns built from diamonds and triangles in every blue you own. Nature is secretly great at geometry."}]},{"day":"Wednesday","focus":"Write It Up","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Scientist's Lab Report","d":"Write up Monday's ice experiment like a real scientist: my question, my prediction, what I did, what happened. Lab reports turn playing around into actual science."},{"t":"Winter Word Bank","d":"Build a bank of winter words starting with this month's letters D, P, and Q — drift, polar, quilt, quiet — then work five of them into one dramatic winter sentence."}]},{"day":"Thursday","focus":"Frozen in Motion","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Freeze Tag Remix","d":"Play freeze tag with a melt rule: frozen players are freed when a teammate circles them twice yelling warm front. Inventing and enforcing new rules together is its own workout."},{"t":"Ice Cube Relay","d":"Set up a relay where each runner balances an ice cube on a spoon across the yard or hallway. Drop it, start over — steady hands under pressure take real practice."}]},{"day":"Friday","focus":"Winter Somewhere Else","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Upside-Down Winter","d":"Here's a puzzle: while we shiver, Australia is in summer. Find both countries on a map and figure out with a grown-up why the seasons flip below the equator."},{"t":"Blizzard Book Nook","d":"Build a cozy blanket nook, stock it with books, and read together for twenty minutes while pretending a blizzard howls outside. The Snowy Day makes a perfect opener."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Winter STEM week — your freezer is the laboratory.","items":["The melt-race setup: three cubes, salt, sugar, and a timer.","Fold-and-cut six-sided snowflakes — count the sides to check.","A D, P, Q word hunt: spot all three letters on labels and signs.","Blizzard reading nook: blankets, flashlight, twenty cozy minutes."]}},{"label":"Week 2 — Winter Animals","days":[{"day":"Monday","focus":"Survival Files","domains":["Scientific Inquiry","Social Studies"],"opts":[{"t":"Animal Survival File","d":"Pick a winter animal — penguin, polar bear, arctic fox — and research how it survives the cold: migrate, hibernate, or adapt. Build a fact file; you're the family expert by Friday."},{"t":"Migration Map Tracing","d":"Trace a real migration route on a map — arctic terns fly from pole to pole every single year. Measure the journey and compare it to a trip your family has taken."}]},{"day":"Tuesday","focus":"Blubber and Fur","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Blubber Glove Test","d":"Coat one plastic bag in butter or shortening, leave another plain, and dunk a hand in each into icy water. Count how many seconds each hand lasts — now you know why whales wear blubber."},{"t":"Huddle Up Experiment","d":"Fill four jars with warm tap water, cluster three together and leave one alone, then check which stays warmest after ten minutes. That's the whole secret of the penguin huddle — and now you have the data to prove it."}]},{"day":"Wednesday","focus":"Publish Your Findings","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Mini Animal Report","d":"Turn your research into a one-page illustrated report or comic strip about your animal's winter survival plan. Give it a headline that would stop a reader cold."},{"t":"Polar Alliteration Poems","d":"Write alliteration lines using this month's letters — dozing deer dream deeply, quiet quails quiver. Silly is allowed; the sound play is doing serious reading work underneath."}]},{"day":"Thursday","focus":"Move Like Survivors","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Animal Survival Circuit","d":"Design a six-station workout based on winter animals — bear crawl, penguin shuffle, wolf lope, rabbit hop — write the station cards, then run the whole circuit twice."},{"t":"Backyard Wildlife Watch","d":"Sit silently outside for ten minutes with a notebook and record every animal you see or hear — even in Florida, winter changes who shows up. Patience is a scientist's superpower."}]},{"day":"Friday","focus":"Expert Hour","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Teach the Family","d":"Present your animal findings at dinner — three facts, your blubber-test results, and one question you still wonder about. Teaching what you learned is how experts are made."},{"t":"Animal Story Swap","d":"Read a winter-animal book with someone — Over and Under the Snow is wonderful — and trade your favorite fact from the week. If a little sibling is around, read a page aloud to them."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your kid becomes a winter-animal expert this week — the freezer and a plastic bag are the lab.","items":["The blubber glove test: butter, two bags, and a bowl of icy water.","An animal fact file card — species, habitat, survival trick, wow fact.","The six-station animal workout, designed and led by your kid.","Friday expert hour: three facts presented at dinner, questions welcome."]}},{"label":"Week 3 — Staying Warm & Cozy","days":[{"day":"Monday","focus":"Tower Challenge","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Snow Tower Challenge","d":"Build the tallest snow tower you can from crumpled white paper, cups, and tape — measure it, record the height, and note what made it wobble. Tomorrow you rebuild it better."},{"t":"Blueprint Before Building","d":"Real engineers draw first. Sketch a labeled blueprint of your tower — base width, number of levels, target height in inches — before you're allowed to touch the tape."}]},{"day":"Tuesday","focus":"Test and Rebuild","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Wind Test Rebuild","d":"Give yesterday's tower a blizzard test — three big breaths or a fan on low. Study where it failed, rebuild it stronger, and test again. Failing, fixing, and retesting is the entire job of engineering."},{"t":"Paper Cup Igloo","d":"Stack paper cups into a dome-shaped igloo, working out how each ring has to shrink and lean inward. Steady hands and patient stacking — this one fights back."}]},{"day":"Wednesday","focus":"Design the Cozy","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Cozy Corner Architect","d":"Design and build the coziest reading corner in the house — blankets, pillows, a lamp, a book basket. A calm spot you built yourself is a calm-down tool that actually gets used."},{"t":"Paper Quilt Squares","d":"Design paper quilt squares using diamond shapes and every shade of blue, then tape them into one family quilt on the wall. Quilt even starts with this month's letter Q."}]},{"day":"Thursday","focus":"Warm Around the World","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"World Warmth Tour","d":"Investigate how people stay warm around the world — heated floors in Korea, saunas in Finland, thick quilts in the mountains. Pick your favorite idea and explain why it's clever."},{"t":"How-To Guide Author","d":"Write a numbered how-to guide: How to Build the Warmest Blanket Fort on Earth. Clear steps, no skipping — then hand it to someone and see if your instructions actually work."}]},{"day":"Friday","focus":"Fort Finale","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Grand Fort Read-In","d":"Build the week's ultimate blanket fort — following your own how-to guide — and hold a family read-in inside by flashlight. Everyone brings a book; twenty minutes minimum."},{"t":"Fort Fact Sheet","d":"Inspect the finished fort like a building official: measure its height and width, count its blankets and pillows, set a maximum occupancy, and publish the official fort fact sheet. Inspectors write reports — that's the job."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Engineering week — towers, igloos, and the coziest corner in the house.","items":["The tower challenge kit: white paper, cups, tape, and a measuring tape.","A blueprint page — engineers draw before they build.","Blue paper diamonds for the family quilt wall.","Friday fort read-in: flashlights on, everyone brings a book."]}},{"label":"Week 4 — Winter Fun","days":[{"day":"Monday","focus":"Winter Photo Walk","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Six-Shot Photo Walk","d":"Take a walk with a camera or phone and capture exactly six signs of winter — bare branches, long shadows, a cool-morning sky. Choosing only six makes you really look."},{"t":"Field Sketch Journal","d":"Take a notebook outside and sketch what winter looks like where you live, labeling what you notice like a naturalist. Drawing slows your eyes down in the best way."}]},{"day":"Tuesday","focus":"Curate the Gallery","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Gallery Curator Day","d":"Pick your best winter photos or sketches, give each a title and a one-line caption, and plan how to display them. Curators decide what deserves the wall — today that's you."},{"t":"Winter Haiku Trio","d":"Write three haiku about your winter pictures — five syllables, then seven, then five. Counting syllables on your fingers is allowed; even poets do it."}]},{"day":"Wednesday","focus":"Games and Records","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Winter Games Trials","d":"Invent a six-event backyard winter games — sock skating, pillow bobsled, paper-snowball toss. Time every event, record the results, and try to beat your own records."},{"t":"Ice Bowling Alley","d":"Freeze water in cups overnight, pop out the ice balls, and bowl at plastic-bottle pins outside. Score real frames — strikes, spares, running totals. Keeping score under pressure is math with a scoreboard."}]},{"day":"Thursday","focus":"Winter Pen Pals","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Warm Wishes Postcards","d":"Make postcards from your winter photos or drawings and mail them to far-away relatives with a note about your January. Real mail from a kid makes a grown-up's whole week."},{"t":"Compare-the-Winters Call","d":"Call or video-chat a relative who lives somewhere colder and swap winter reports — their snow boots versus your flip-flops. Ask what they love most about their winter."}]},{"day":"Friday","focus":"Close the Journal","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Wondered and Learned","d":"Reread your whole January journal and write one closing page: three things I wondered, three things I learned, one goal I'm not giving up on. That's the power of yet, on paper."},{"t":"Family Slideshow Night","d":"Host a closing slideshow of the month's photos, experiments, and forts, then end with a cozy read-aloud — and if feelings from the month come up, Mrs. Bear's Your Feelings Matter is a lovely last chapter."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Winter arts week — cameras, journals, and one proud family slideshow.","items":["The six-shot challenge: exactly six winter photos, chosen with care.","A haiku card — five, seven, five syllables about winter.","Freeze cups of water tonight — tomorrow they're bowling balls for bottle pins.","Friday slideshow night, closed with a family read-aloud."]}}]},"feb":{"theme":"Kindness & Friendship","weeks":[{"label":"Week 1 — What Is a Friend?","days":[{"day":"Monday","focus":"Define a Friend","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Friend Recipe Card","d":"Write a recipe for a great friend — three ingredients, two steps, one warning label. Read it aloud at dinner and see if the family agrees. Naming friendship qualities helps kids notice them in real life."},{"t":"Friendship Interview","d":"Interview the oldest person in your house about their longest friendship. Take reporter notes: how they met, one rough patch, why it lasted. Real stories teach more than any lecture."}]},{"day":"Tuesday","focus":"The Pledge","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Write Your Pledge","d":"Draft a personal friendship pledge — three promises you can actually keep, like sticking up for people. Sign it, date it, and post it by your bed. A named promise is easier to keep."},{"t":"Pledge Poster","d":"Turn your pledge into a poster with fancy lettering and a border of hearts — pink and red if you have them. Hanging your words where you see them daily turns them into habits."}]},{"day":"Wednesday","focus":"Friendship by Numbers","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Seven Friend Facts","d":"List seven facts a good friend would know about you, then quiz a sibling or parent. Seven is this month's number — see who scores seven out of seven."},{"t":"Friendship Map","d":"Map your friendship circle: you in the middle, friends, family, and neighbors in rings around you. Count who lands in each ring. Seeing the whole web reminds kids how many people are in their corner."}]},{"day":"Thursday","focus":"Friends in Motion","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Partner Fitness Challenge","d":"Invent a seven-move partner workout with someone at home — high fives count as a rep. Write the moves down, then coach each other through two rounds. Coaching is friendship practice with a heartbeat."},{"t":"Trust Walk","d":"Set up a soft obstacle path, then guide a blindfolded family member through it using only words — then swap. Clear directions plus trust equals teamwork you can actually feel."}]},{"day":"Friday","focus":"Friendship Science","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Smile-Back Study","d":"Run a mini experiment: smile and greet everyone you pass today, and tally how many smile back. Predict your results first, then compare. Kindness data is still data."},{"t":"Read and Rate","d":"Read a friendship story together tonight — reading to a younger sibling counts double. Then rate the characters: who was a good friend, who wasn't, and what's your evidence?"}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship starts at the dinner table — here are this week's little moments.","items":["Ask at dinner: what makes someone a good friend? Everyone answers, youngest first.","Post the friendship pledge on the fridge and let the whole family sign it.","Hunt for the letters R, U, and V on cereal boxes and mail — first to seven wins.","Trade stories at bedtime: one kind moment you saw today, one you'd like a do-over on."]}},{"label":"Week 2 — Kind Words & Deeds","days":[{"day":"Monday","focus":"Kindness Mission","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Secret Agent Kindness","d":"Pick a family member and do three sneaky kind things for them today — folded laundry, a hidden note, a made bed. Stay undercover until dinner. Kindness without credit is the advanced level."},{"t":"Kindness Jar Launch","d":"Start a family kindness jar: every kind act spotted earns a paper slip inside. Set a goal of seven slips by Friday and plan a small family celebration when you hit it."}]},{"day":"Tuesday","focus":"Words That Lift","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Compliment Cards","d":"Write a real, specific compliment card for each person in your house — plain old nice is banned, so dig deeper. Deliver them at dinner. Specific praise lands harder than generic praise."},{"t":"Kind Words Wall","d":"Build a word wall of lifting words starting with this month's letters — respect, understanding, value. Add one new word each day this week. Bigger vocabulary gives kindness more tools."}]},{"day":"Wednesday","focus":"Count Your Kindness","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Kindness Tally","d":"Keep a pocket tally sheet all day: one mark every time you see or do something kind. Graph the results tonight, morning versus afternoon. Where does kindness peak in your house?"},{"t":"Dinner Helper Chain","d":"Pick tonight's dinner and count every invisible helper behind it — farmer, trucker, grocer, cook — drawing the chain link by link. How long does it get? Kindness starts with noticing how many hands help you daily."}]},{"day":"Thursday","focus":"Kindness in Motion","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Heavy Lifting Hero","d":"Claim the heavy jobs all week — laundry baskets up the stairs, grocery bags in from the car, recycling to the curb — and tally your total loads. Strength that serves somebody is the best kind of workout."},{"t":"Deliver a Smile","d":"Walk a drawing or friendly note over to a neighbor you know, with a grown-up along. A two-minute delivery can flip someone's whole day — and yours."}]},{"day":"Friday","focus":"Kindness Report","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Bucket Book Review","d":"Read a kindness story tonight — or read one aloud to a younger kid, big-kid style. Then write a one-sentence review: did the characters fill buckets or dip into them?"},{"t":"Ripple Effect Test","d":"Test the kindness ripple: do one kind act in the morning and quietly track what happens next. Did it spread? Scientists call kindness contagious — see if your data agrees."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week the whole family catches kindness — here's how to keep it spreading.","items":["Keep the kindness jar somewhere everyone passes — a full jar earns family movie night.","Say one specific compliment to each person before bed and watch what it does to bedtime moods.","Slip a kind note into a lunchbox, bag, or coat pocket tomorrow morning.","Play kind-word alphabet in the car: R is for respect, U is for understanding — make it to V."]}},{"label":"Week 3 — Working Together","days":[{"day":"Monday","focus":"Team Builds","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Cup Tower Challenge","d":"Build the tallest tower you can from cups or boxes — but every builder may only use one hand. Teamwork gets real the moment nobody can do it alone."},{"t":"Silent Fort Build","d":"Team up to build a blanket fort in total silence — gestures only. Debrief after: what worked, what flopped? Communication is a lot more than talking."}]},{"day":"Tuesday","focus":"Lead the Team","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Project Manager Day","d":"Pick a small family project — reorganize the game shelf, plan Saturday morning — and manage it start to finish: assign jobs, set the deadline, check the work. Managers make sure every helper knows their part."},{"t":"Team Rules Draft","d":"Draft a family teamwork code — five rules everyone can live with — then hold a vote. Voting is how teams make fair calls when people disagree."}]},{"day":"Wednesday","focus":"Cooperative Games","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Board Game Alliance","d":"Play a board game in teams of two, planning moves together in whispers. Winning together beats winning alone — and negotiating a move is a life skill in disguise."},{"t":"Puzzle Split","d":"Split a puzzle or a big job into fair shares — count the pieces, divide by helpers, then race the clock together. Fair splitting is math you can argue about, then agree on."}]},{"day":"Thursday","focus":"Crew Projects","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Marble Run Team","d":"Engineer a ball run down a wall or staircase using tape and cardboard tubes — one person designs, one builds, one tests, then rotate jobs. Rotating roles is how teams stay fair."},{"t":"Recipe Crew","d":"Make a simple snack as a crew: one reads the steps, one measures, one assembles. Follow the order exactly, then rate the result. Every kitchen is secretly a teamwork lab."}]},{"day":"Friday","focus":"Celebrate the Team","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Team Trophy Craft","d":"Design a trophy from foil and cardboard for your family team, and award it with a short speech about this week's best teamwork moment. Naming wins makes teams hungry for more of them."},{"t":"Read-Aloud Duo","d":"Pick a book and tag-team the read-aloud — you take one page, your partner takes the next, full character voices required. Shared reading is teamwork for your brain."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week your house becomes one team — here's the playbook.","items":["Assign this week's chores draft-pick style — captains alternate choosing jobs, not people.","Play one cooperative game where the family wins or loses together.","Cook one meal with every person owning one job, start to finish.","Count teamwork wins at dinner — can the family spot seven in one week?"]}},{"label":"Week 4 — Hearts & Helpers","days":[{"day":"Monday","focus":"Spot the Helpers","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Helper Spotlight","d":"List the helpers your family counts on — mail carrier, crossing guard, coach, teacher. Pick one and write three ways their job helps your street. Noticing helpers is step one to becoming one."},{"t":"Thank-You Plan","d":"Choose one helper to thank this week and plan it like a project: what you'll make, when you'll deliver it, who's driving. Kids can absolutely run a plan start to finish."}]},{"day":"Tuesday","focus":"Cards from the Heart","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Card Factory","d":"Set up a card assembly line: fold, decorate with hearts, write the message, sign. Make a stack for neighbors, a nursing home, or the school front office. Handmade beats store-bought every time."},{"t":"Pop-Up Hearts","d":"Engineer a pop-up card — cut two slits in the fold, push the tab through, and glue a heart on top. A little paper engineering makes your kindness jump off the page."}]},{"day":"Wednesday","focus":"Giving Math","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Charity Stand Plan","d":"Design a lemonade or cookie stand for charity on paper: set the prices, calculate what twenty sales would earn, and pick the cause that gets the money. Whether or not it ever gets built, the math is real."},{"t":"Kindness Budget","d":"You have sixty pretend minutes of helping time this week — budget it. How many minutes go to which helpers? Chart it out. Time is the realest thing anyone can give."}]},{"day":"Thursday","focus":"Heart Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Letter to a Hero","d":"Write a real letter to someone whose job helps people — thank them with details, not just a plain thanks. Address the envelope yourself. Mail with a stamp still amazes people."},{"t":"Feelings Journal Night","d":"Start an older-kid feelings journal tonight: one page about a time someone helped you when you were low. Mrs. Bear's Your Feelings Matter is a great springboard if it's on your shelf."}]},{"day":"Friday","focus":"Reflect and Measure","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Month in Data","d":"Look back at the kindness jar or tally: graph the month, find your family's kindest day, and predict what March will look like. Reflection turns one good month into a habit."},{"t":"Warm Fuzzy Lab","d":"Rank your top seven kind acts from this month and ask the family to vote on which got the biggest smile. Comparing results is exactly what real researchers do."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap the month by sending all that kindness out the front door.","items":["Deliver the family's cards together — let the kids do the handing over and the talking.","Hear the charity-stand pitch at dinner and let the family vote on the cause together.","End the month with a kindness story read together — Have You Filled a Bucket Today? is a lovely pick.","Trace hearts around the house — can you find seven, our number of the month?"]}}]},"mar":{"theme":"Things That Grow","weeks":[{"label":"Week 1 — Seeds & Plants","days":[{"day":"Monday","focus":"Start the Experiment","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Bag Greenhouse","d":"Fold a damp paper towel around a few dried beans, seal it in a clear bag, and tape it to a sunny window. Label it with today's date. You just built a greenhouse for under a dime."},{"t":"Sprout Predictions","d":"Before anything grows, write your predictions in a notebook: how many days to sprout, which seed wins, how long the root gets by Friday. Scientists guess first, then check."}]},{"day":"Tuesday","focus":"Chart the Growth","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Growth Data Chart","d":"Set up a measuring chart for your seeds: date, millimeters, and a quick sketch each day. Eight days of data — this month's number — tells a story that numbers alone can't."},{"t":"Seed Journal Setup","d":"Start a seed journal with a page per day: the date, one observation, and one question you're wondering about. Wondering on paper is how scientists actually think."}]},{"day":"Wednesday","focus":"Inside a Seed","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Seed Dissection","d":"Soak a large bean for a few hours, then gently split it open and find the baby plant hiding inside. Sketch what you see — in purple if you've got it. Every seed is a lunchbox with a passenger."},{"t":"Diagram Poster","d":"Draw a big cutaway diagram of a seed becoming a plant — roots down, shoot up, labels everywhere. Teaching your drawing to someone else locks the science in for good."}]},{"day":"Thursday","focus":"Growing Strong","domains":["Physical Development","Social Studies"],"opts":[{"t":"Garden Boot Camp","d":"Invent a gardener's workout — digging squats, watering-can arm raises, wheelbarrow walks across the room. Eight reps each, two rounds. Strong gardeners grow strong gardens."},{"t":"Farm to Table Trace","d":"Pick one food from tonight's dinner and trace its route: farm, truck, store, kitchen. Draw the map. Every meal took a road trip to reach your plate."}]},{"day":"Friday","focus":"Patience Practice","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Slow News Report","d":"Write a breaking-news report on your bean bag — interviews with the beans optional, humor encouraged. Reporting on very slow news teaches patience with a wink."},{"t":"Waiting Well Read","d":"Read The Tiny Seed or any plant story together tonight, and talk about the waiting parts. Seeds and kids both grow on their own schedule — that's the week's real lesson."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your windowsill becomes a science lab this week — here's the family's part.","items":["Tape the bean bag where the family passes daily and get a one-line sprout report at dinner.","Hunt for the letters I, X, and Z on food labels — Z is the tough one; pizza helps.","Mark everyone's height on a door frame — kids are things that grow too.","Predict together: how many of your eight seeds will sprout? Winner picks Friday dessert."]}},{"label":"Week 2 — In the Garden","days":[{"day":"Monday","focus":"Plant Your Garden","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Windowsill Farm","d":"Plant seeds in yogurt cups or an egg carton with holes poked in the bottom. Line your farm up in the sun and give each cup a name. Ownership is what grows gardeners."},{"t":"Kitchen Regrow Lab","d":"Stand the cut end of green onions, celery, or lettuce in a shallow cup of water. New growth shows up within days — food scraps are secretly seeds' cousins."}]},{"day":"Tuesday","focus":"Garden Design","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Dream Garden Blueprint","d":"Design a dream garden on paper: an oval bed for flowers — this month's shape — rows for vegetables, and a path for the watering crew. Blueprints first; that's how real projects start."},{"t":"Plant Marker Craft","d":"Craft plant markers from painted rocks or taped-on spoons — name each plant and add its planting date. A labeled garden is a managed garden."}]},{"day":"Wednesday","focus":"Water Wisdom","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Water Duty Roster","d":"Build the family watering schedule: who waters what, which days, how much. Post it and run it all week. Keeping something alive is real responsibility, not pretend."},{"t":"Thirsty Plant Test","d":"Water one plant cup on schedule and skip another for two days — observe, sketch, compare, then rescue the thirsty one. One fair test beats a hundred guesses."}]},{"day":"Thursday","focus":"Garden Workout","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Digging Crew","d":"Take on a real outdoor job: pull weeds, loosen soil with a spoon or trowel, haul the watering can. Twenty minutes of garden work counts as a full workout."},{"t":"Bug Patrol","d":"Patrol the yard or sidewalk cracks for garden creatures — worms, ants, roly-polies. Tally what you find and where. Every garden runs on tiny employees."}]},{"day":"Friday","focus":"Garden Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Community Garden Scout","d":"Find out where the nearest community garden or farmers market is and plan a weekend visit with your family. Gardens feed neighborhoods, not just backyards."},{"t":"Read and Sketch","d":"Read Planting a Rainbow or any garden book together, then sketch the flowers you'd plant — purple ones earn bonus points this month. Books plant ideas the way gardeners plant seeds."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Everybody gets a little green thumb this week — dirt under the nails encouraged.","items":["Give every family member one plant to keep alive this month — name tags encouraged.","Visit a farmers market or garden center this weekend and let kids ask a grower one question.","Regrow green onions on the windowsill — it's dinner and a science show in one.","Practice writing I, X, and Z with a stick in dirt or a finger in a tray of flour."]}},{"label":"Week 3 — Baby Animals","days":[{"day":"Monday","focus":"Life Cycle Research","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Pick Your Animal","d":"Choose one animal and become the house expert on its life cycle. Gather three facts from books or a grown-up-approved search, and rank the weirdest one. Experts start with curiosity."},{"t":"Life Cycle Wheel","d":"Make a spinning life cycle wheel from two paper circles joined with a paper fastener or clip — egg, baby, teen, adult. A wheel shows what a list can't: the cycle never ends."}]},{"day":"Tuesday","focus":"Animal Words","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Baby Name Quiz","d":"What's a baby kangaroo called? A baby fox? Build an eight-question quiz with a score sheet and crown a family champion. Joey, kit — the answers are wilder than you'd guess."},{"t":"Zoo Word Builder","d":"Build animal words with this month's letters: I is for iguana, X marks the fox and the ox, Z is for zebra. Write a zoo roster that uses all three."}]},{"day":"Wednesday","focus":"Animal Art","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Clay Critter Studio","d":"Sculpt a baby animal and its parent from play-dough or foil. Notice what's different — size, proportions, those big baby eyes. Artists observe before they build."},{"t":"Growth Flip Book","d":"Draw a flip book of an animal growing up — tadpole to frog works great, one small change per page. Flip it fast and watch years pass in two seconds."}]},{"day":"Thursday","focus":"Animal Athletics","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Animal Olympics","d":"Run a backyard Animal Olympics: frog long jump, bear crawl race, flamingo balance-off. Measure and record every result and start a family record book for eight events."},{"t":"Hide and Seek Science","d":"Hide eight small objects in plain sight — some matching their background, some not — and time how fast a searcher finds each one. Blending in is survival math."}]},{"day":"Friday","focus":"Animal Families","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Who Raises Who","d":"Research how one animal parent raises its babies — penguin dads, wolf packs, kangaroo pouches — and share the best fact at dinner. Families come in every shape in nature too."},{"t":"Read to the Littles","d":"Practice leadership: read an animal story aloud to a younger sibling or cousin with full character voices — a Bear Phonics reader like Feed Me works great. Big kids reading to little kids is Mrs. Bear's favorite kind of leadership."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Baby animals are the hook — life cycles are the lesson hiding inside.","items":["Watch a five-minute baby-animal video together and count the life cycle stages.","Hold a quiz night on baby animal names — the champion picks the weekend show.","Spot animal families outside: birds, squirrels, lizards. Who's feeding who?","Draw your family as animals — which furry, feathered, or scaly crew are you?"]}},{"label":"Week 4 — Growing Me","days":[{"day":"Monday","focus":"Set the Goal","domains":["Approaches to Learning","Social & Emotional Development"],"opts":[{"t":"One Big Goal","d":"Pick one personal growth goal for the next four weeks — ride without training wheels, finish a chapter book, learn eight new words in another language. Write it where you'll see it daily. Goals you can see, you chase."},{"t":"Stepping Stone Plan","d":"Draw your goal as four stepping stones across a river — one stone per week between today-you and goal-you, each labeled with its step. Big things get crossed one stone at a time."}]},{"day":"Tuesday","focus":"Track the Data","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Progress Graph","d":"Set up a progress graph for your goal — practice minutes, pages read, or baskets made each day. Watching your own line climb beats any prize sticker."},{"t":"Then and Now Math","d":"Do the math on how you've grown: inches since last year, shoe sizes, books finished. Interview a parent for your baby stats and calculate the difference. You're a walking growth chart."}]},{"day":"Wednesday","focus":"Growth on Paper","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Now and Then Page","d":"Split a journal page down the middle: last-year me on the left, today-me on the right — what you could do, worried about, loved. Write or draw the differences. Growth is easier to believe when it's on paper."},{"t":"Talent Show Poster","d":"Make a poster advertising the skill you're growing — coming this spring: two-wheel rider. Hang it up as a promise to yourself. A little hype helps the hustle."}]},{"day":"Thursday","focus":"Practice Day","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Ten-Minute Training","d":"Put ten focused minutes into your goal today — timer on, no screens, no quitting early. Then log it on your graph. Ten real minutes beats an hour of halfway."},{"t":"Family Fitness Test","d":"Run a family fitness check-in: jumping jacks in a minute, longest plank, farthest hop. Record everyone's numbers to beat next month. Growing bodies love a rematch."}]},{"day":"Friday","focus":"Celebrate Growth","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Growth Interview","d":"Interview a grown-up about something hard they learned — driving, cooking, a new language, a new job. Ask what kept them going. Every adult you know was once a beginner."},{"t":"Week One Report","d":"Report your week-one progress to the family like a news anchor, graph and all, then read a favorite book together as the closing celebration. Progress shared is progress doubled."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week the thing that grows is your kid — water accordingly.","items":["Post everyone's growth goal on the fridge — grown-ups pick one too; kids love holding parents to it.","Mark heights on the door frame again at month's end and compare to week one.","Ask at dinner: what can you do this March that you couldn't do last March?","Trace an oval — this month's shape — around family baby photos for a then-and-now wall."]}}]},"apr":{"theme":"Our Big Blue Earth","weeks":[{"label":"Week 1 — Land & Water","days":[{"day":"Monday","focus":"Waste Audit","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Trash Detective","d":"Run a one-day waste audit at home: tally what goes in the trash by type — paper, plastic, food, other. Present your findings at dinner with one recommendation. Auditors change the world with clipboards."},{"t":"Junk Drawer Census","d":"Count and sort one junk drawer or bin: keep, recycle, donate, toss. Chart the results. Every cleanup starts with knowing what you've actually got."}]},{"day":"Tuesday","focus":"Map the Planet","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Blue Marble Map","d":"Draw Earth from space — mostly teal water, patches of green and brown land. Estimate the split before you check: it's about seventy percent water. Our planet's nickname is honest."},{"t":"Watershed Model","d":"Crumple paper into mountains, mark the ridge lines with washable marker, and spritz with water to watch the rain find the rivers. Every drop is headed somewhere — that's why litter travels."}]},{"day":"Wednesday","focus":"Outdoor Cleanup","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Yard Sweep Crew","d":"Grab gloves and a bag and sweep your yard, porch, or sidewalk for litter with a grown-up along. Count your haul when you're done. Ten minutes outside, one cleaner corner of Earth."},{"t":"Follow the Water","d":"Take a walk to find where water goes on your street — gutters, drains, puddles, ditches — and map the route. Storm drains lead to real creeks, which is why they're not trash cans."}]},{"day":"Thursday","focus":"Earth Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Y Word Collection","d":"Collect Y words for your Earth journal — yard, year, yellow sun. Then run a review lightning round: one Earth word for every letter you can manage. Word collectors make strong writers."},{"t":"Nine-Line Poem","d":"Write a nine-line poem about land and water — one line for each thing you'd protect. Nine is this month's number, and poems count as projects too."}]},{"day":"Friday","focus":"Water Lab","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Oil Spill Lab","d":"Float a spoonful of cooking oil on a bowl of water, then test cleanup tools — spoon, cotton ball, paper towel — and rank what works best. Now you know why ocean spills are the hardest cleanup on Earth."},{"t":"Read the Earth","d":"Read The Earth Book or any planet-friendly story together tonight, and pick one idea from it your family will actually try. Books work best when they leak into real life."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week the family looks at land and water with fresh eyes — starting at your own curb.","items":["Post the waste-audit results on the fridge and pick one thing to cut this month.","Walk to the nearest storm drain together and talk about where it leads.","Time showers this week — a family racing the clock saves real gallons.","Spot the letter Y on nine signs, labels, or license plates around town."]}},{"label":"Week 2 — Reduce, Reuse, Recycle","days":[{"day":"Monday","focus":"Sort It Out","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Recycle Command Center","d":"Set up labeled home recycling stations — paper, plastic, metal — and teach the family the rules with a one-minute demo. You're the recycling captain now, and captains train their crews."},{"t":"Sorting Speed Trials","d":"Race the clock sorting a bag of clean recyclables into the right bins. Log your time, then try to beat it tomorrow. Fast sorting is how it actually gets done."}]},{"day":"Tuesday","focus":"Upcycle Studio","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Cardboard Invention","d":"Turn a cardboard box into something useful — a desk organizer, a marble maze, a bird feeder a grown-up helps you hang. Before anything hits the bin, ask: could this be something first?"},{"t":"Trash to Treasure","d":"Give one throwaway item a second job: jar to pencil cup, old shirt to cleaning rag, lid to paint palette. Test it for a week and report whether it holds up. Real inventors test."}]},{"day":"Wednesday","focus":"Recycle Math","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Bottle Count Forecast","d":"Count this week's bottles and cans, then multiply by fifty-two. That yearly number is your family's footprint — and your before-and-after challenge. Math makes invisible things visible."},{"t":"Lighter Lunch Challenge","d":"Count the packaging in one packed lunch, then redesign it to cut the trash — reusable containers, whole fruit. Compare before and after. Engineers optimize."}]},{"day":"Thursday","focus":"Spread the Word","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Persuasion Letter","d":"Write a persuasive note proposing one new green habit for your family — give two reasons and answer one likely objection. Persuading people kindly is a leadership superpower."},{"t":"Reuse Story Swap","d":"Trade books you've finished with a friend or neighbor instead of buying new, and read your trade together tonight. Reusing stories counts as recycling too."}]},{"day":"Friday","focus":"Collection Day","domains":["Physical Development","Social Studies"],"opts":[{"t":"Curbside Crew","d":"Own the recycling job this week: collect the bins, roll them to the curb, bring them back. Real responsibility, real muscles, real help — nine minutes, tops."},{"t":"Donation Box Run","d":"Fill one box with outgrown clothes or toys and ride along to donate it. Reuse works best when things land with people who need them."}]}],"homeden":{"title":"The Home Den — This Week","lead":"The three Rs move in with your family this week — let the kids run the show.","items":["Let the kids run the recycling bins to the curb this week — it's their department now.","Do one upcycle project together; the cardboard-box invention is a family favorite.","Swap outgrown books with another family instead of buying new ones.","Count the bottles and cans you skip this week by using refillables — aim for nine."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Station","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Bottle Barometer","d":"Stretch plastic wrap tight over a jar, rubber-band it, and tape a straw pointer on top — mark where it points each day. Rising or falling means the air pressure is changing, and pressure is tomorrow's weather whispering."},{"t":"Microclimate Map","d":"Hunt your yard or block for its warmest and coolest spots — sunny wall, deep shade, breezy corner — and map the microclimates with a color key. Weather isn't one thing, even on one street."}]},{"day":"Tuesday","focus":"Forecast Face-Off","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Forecast Showdown","d":"Challenge the weather app: you and the app each write tomorrow's forecast tonight, then score both against the real sky all week. Keep a win-loss tally — beating the professionals even once earns permanent bragging rights."},{"t":"Cloud Cover Fractions","d":"Estimate what fraction of the sky the clouds cover — half, a quarter, nearly all — at morning and evening, and chart the fractions for nine days. The sky is a math lesson that never repeats itself."}]},{"day":"Wednesday","focus":"Sky Art","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Water Cycle Bag","d":"Draw a sun and cloud on a zip-top bag, add a splash of blue-tinted water, seal it, and tape it to a sunny window. Watch it evaporate, fog up, and rain down the sides — the whole water cycle in one bag."},{"t":"Crescent Moon Watch","d":"Check the moon tonight and sketch its shape — crescent is this month's shape. Keep sketching for a week and watch it change. The sky keeps a calendar if you keep looking."}]},{"day":"Thursday","focus":"Weather in Motion","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Storm Drill Captain","d":"Lead a family severe-weather drill: pick the safe spot, assign jobs, time the practice. In Florida, storm-smart kids are a real asset — calm comes from practice."},{"t":"Wind Sprint Test","d":"Test the wind with your body: run the same short sprint with the wind, then against it, and compare your times. Invisible air pushes back — now you've felt the data."}]},{"day":"Friday","focus":"Sky Stories","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Weather Myth Busters","d":"Collect weather sayings from grown-ups — red sky at night, cows lie down before rain — and investigate whether each one holds up. Rate them confirmed, busted, or needs more data. Folk wisdom versus evidence is real science."},{"t":"Porch Sky Reading","d":"Take books out to the porch or a window seat before dinner and read until the first star shows, then trade one favorite line each. Weather-watching and reading make good porch partners."}]}],"homeden":{"title":"The Home Den — This Week","lead":"All eyes on the sky this week — the forecast calls for curiosity.","items":["Check the jar barometer each morning and let the kids call rising or falling.","Watch one sunset this week from the porch or a window — phones down, eyes up.","Find the crescent moon and let the kids explain why it changes shape.","Let a kid deliver the morning forecast before school — accuracy scores optional."]}},{"label":"Week 4 — Caring for Our Earth","days":[{"day":"Monday","focus":"Earth Day Plan","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Project Pitch","d":"Plan your own Earth Day project like a boss: pick the project, list the steps and supplies, set the day. Then pitch it to the family for approval. Every big change starts as somebody's plan."},{"t":"Earth Promise Contract","d":"Write a family Earth contract — three promises, like lights off and shorter showers — and have everyone sign it. Post it where the most-used light switch lives."}]},{"day":"Tuesday","focus":"Plant Something","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Tree or Seed Day","d":"Plant something real — a seed, a kitchen scrap, or a young plant in a pot or a yard corner. Name it, water it, own it. The best time to plant was yesterday; the second best is today."},{"t":"Pollinator Rest Stop","d":"Set out a shallow dish of water with pebble landing pads for bees and butterflies, near flowers if you have them. Tiny pollinators do giant work — give the crew a rest stop."}]},{"day":"Wednesday","focus":"Energy Detectives","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Phantom Power Patrol","d":"Patrol the house counting things using power that nobody's using — lights, chargers, glowing screens. Report the count, then run a switch-off sweep every night this week. Detectives save real money."},{"t":"Rank the Green Moves","d":"List nine energy-saving moves and rank them from easiest to hardest, then commit to your top three. Ranking choices is how smart teams decide where to spend their effort."}]},{"day":"Thursday","focus":"Earth Art","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Found Object Mural","d":"Create a mural or sculpture from clean bottle caps, scraps, and packaging headed for the bin. Give it a title and host a two-minute gallery talk. Art can argue for the Earth."},{"t":"Thank You, Earth","d":"Write and decorate a thank-you card to the planet naming nine things it gives you for free. Hang it by the door as a daily reminder. Gratitude is where care starts."}]},{"day":"Friday","focus":"Action Day","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Run the Project","d":"Run the Earth Day project you planned on Monday — cleanup, planting, donation drive — with the whole family on your crew. Take before-and-after photos. Leaders finish what they start."},{"t":"Celebrate and Read","d":"Celebrate the month with a picnic — a blanket in the living room counts — and read We Are Water Protectors or a favorite Earth story aloud. Then each person shares one habit they're keeping."}]}],"homeden":{"title":"The Home Den — This Week","lead":"The month ends with action — the kids lead, the grown-ups follow.","items":["Run the kids' Earth Day project as a family — they're the project managers this time.","Sign the family Earth contract and tape it beside the most-used light switch.","Keep one green habit going into May — let each person pick theirs.","Count nine things outside that need clean air or water — the crescent moon's sky can be one."]}}]},"may":{"theme":"On the Move","weeks":[{"label":"Week 1 — Things That Go","days":[{"day":"Monday","focus":"Vehicle Design Lab","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Junk-Box Racer","d":"Raid the recycling bin and challenge your child to build a car that actually rolls — cardboard, bottle caps, tape, whatever works. Testing and rebuilding is real engineering thinking."},{"t":"Dream Machine Blueprint","d":"Have them sketch an invented vehicle with labeled parts, then explain how each part helps it move. Labeling a diagram is exactly how designers and scientists share big ideas."}]},{"day":"Tuesday","focus":"Speed Trials","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Ten-Second Derby","d":"Set a start line and see how far toy cars — or yesterday's junk-box racer — travel in ten seconds. Record each run, then ask what one change might make it faster."},{"t":"Wheel Count Challenge","d":"During errands or a walk, tally vehicles by wheel count — two, four, six, eighteen — and total all the wheels at the end. Mental math sneaks in while they think they're just spotting trucks."}]},{"day":"Wednesday","focus":"Journeys and Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Transport Journal Entry","d":"Start a week-long journal: today, write about the most interesting vehicle they have ever ridden and where it took them. Journaling builds writing stamina one honest page at a time."},{"t":"Vehicles Around the World","d":"Look up how kids get to school in other countries — water taxis, cable cars, rickshaws — and talk about which they would choose. It stretches geography and perspective at the same time."}]},{"day":"Thursday","focus":"Body in Motion","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Locomotion Lab","d":"Challenge them to invent three brand-new ways to travel across the yard without walking — crab shuffle, log roll, side slide — then teach you the best one. Inventing movement is problem-solving with your whole body."},{"t":"Paper Plane Trials","d":"Fold two different paper airplane designs and test which flies farther over five throws each. Comparing averages is exactly how engineers decide which design wins."}]},{"day":"Friday","focus":"Share the Ride","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Showcase and Story","d":"Have your child present this week's best build to the family: what it does, what failed, and what they fixed. Talking about setbacks out loud builds real confidence and courage."},{"t":"Traffic Comic Strip","d":"Have them draw a comic strip of the week's builds and test runs — the crash, the fix, the victory lap — one rainbow color per panel. Then read a favorite book together to close the week, driver's choice."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tape this to the fridge — a week of things that go, no batteries required.","items":["Keep a shoebox of recycling-bin build parts ready for quick engineering sessions.","Play the alphabet road-trip game: spot letters A to Z in order on signs during any drive.","Ask at dinner: which invention changed travel the most — wheels, wings, or engines?","Ten minutes of reading before screens — travel and vehicle books count double this month."]}},{"label":"Week 2 — On Land","days":[{"day":"Monday","focus":"Map My Route","domains":["Social Studies","Mathematical Thinking"],"opts":[{"t":"Route to School","d":"Have your child draw the route from home to school from memory, marking turns and landmarks, then check it against a real map. Comparing memory to reality sharpens spatial thinking fast."},{"t":"Bird's-Eye Bedroom","d":"Challenge them to map their bedroom from above, roughly to scale, with a key of symbols for the furniture. Map keys are a secret code every geographer learns to write."}]},{"day":"Tuesday","focus":"Travel Writer","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Hometown Brochure","d":"Have them design a travel brochure for your own town — top three sights, best snack stop, one hidden gem. Persuasive writing comes easier when you're already the expert."},{"t":"Postcard to a Friend","d":"Write and decorate a postcard from an imaginary road trip, describing exactly what they saw out the window. Descriptive details are the muscle of good writing."}]},{"day":"Wednesday","focus":"Navigator's Walk","domains":["Physical Development","Social Studies"],"opts":[{"t":"You're the Navigator","d":"On a family walk, hand over the directions: your child chooses every turn and has to get you home a new way. Leading the route builds confidence and a mental map at once."},{"t":"Compass Points Workout","d":"Call out compass moves in the yard — three jumps north, lunge east, gallop south. It anchors north, south, east, and west in the body, not just on paper."}]},{"day":"Thursday","focus":"Distance Detectives","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Pace-Count Survey","d":"Have them measure the driveway or hallway in paces, then in feet with a tape measure, and compare the two counts. Discovering why standard units matter beats being told."},{"t":"Ten-Landmark Ranking","d":"Pick ten landmarks on a map of your area and rank them from nearest to farthest from home. Ordering by distance is number-line thinking in disguise, and ten is this month's number."}]},{"day":"Friday","focus":"Trip Planners","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Dream Trip Pitch","d":"Let your child plan a pretend family trip — destination, route, packing list, budget-ish guesses — and pitch it at dinner. Fielding the family's questions is gentle practice in courage."},{"t":"Atlas Blanket Night","d":"End the week under a blanket with an atlas or travel book, reading together about one place nobody in the family has ever been. Wondering together is the whole point."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pin this up — a week of maps, routes, and young navigators.","items":["Let your child navigate one real errand this week, turn by turn.","Hide a small treat and have them draw a five-step treasure map for a sibling or grown-up to follow.","Ask at dinner: if we drove ten hours in any direction, where could we reach?","Read a story set somewhere far away and find that place on a map together."]}},{"label":"Week 3 — On Water & Air","days":[{"day":"Monday","focus":"Boat Builders","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Penny Cargo Boats","d":"Fold foil into little boats and test how many pennies each holds before sinking — water play stays within arm's reach. Redesigning after a sink is the whole lesson."},{"t":"Sail Power Test","d":"Add a paper sail to a floating dish and race it across a basin by blowing through a straw. Ask why a bigger sail catches a bigger push."}]},{"day":"Tuesday","focus":"Ramp Science","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Ramp Height Trials","d":"Prop a cardboard ramp at three heights and measure how far a toy car rolls from each, recording results in a quick chart. Height in, distance out — that's real physics data."},{"t":"Friction Face-Off","d":"Race the same car down the ramp onto carpet, tile, and a towel, and compare how far it travels on each. Naming friction gives kids a word for something they can already feel."}]},{"day":"Wednesday","focus":"Air in Action","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Parachute Drop Design","d":"Build parachutes from a plastic bag, string, and a small toy, then test drops from a safe step. Slower is the win here — ask what caught the air."},{"t":"Straw Rocket Gallery","d":"Design paper rockets that launch off a straw with one strong puff, then decorate and name each model before test flights. Art and aerodynamics share the table tonight."}]},{"day":"Thursday","focus":"Moving the World","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Ships That Changed Everything","d":"Read together about a famous ship, plane, or bridge, then have your child write three facts and one question in their journal. Questions are where real research starts."},{"t":"Interview a Traveler","d":"Have your child interview a grandparent or neighbor about the longest trip they ever took, and write down the best detail. Family stories are living history."}]},{"day":"Friday","focus":"Forces and Art","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Chain Reaction Challenge","d":"Challenge your child to build a chain reaction across the floor — a domino line of books, a rolling car, a falling spoon — that ends by toppling a paper flag. Plan it, watch it fail, tweak it, and cheer the run that finally works."},{"t":"Pentagon Prize Medals","d":"Cut paper pentagons — this month's shape — and award them as medals for the week's best builds: sturdiest boat, farthest roll, slowest parachute. Celebrating effort out loud makes kids braver next time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of splashes, launches, and why-did-that-happen — all supplies from the kitchen.","items":["Keep water experiments in the sink or a basin, always within arm's reach.","Ask in the car: what is pushing or pulling us right now?","Save straws, foil, and plastic bags in a flight-and-float supply box.","Read one page about a famous inventor or explorer before lights-out."]}},{"label":"Week 4 — How I Move","days":[{"day":"Monday","focus":"Course Designer","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Obstacle Course Architect","d":"Hand over full design control: your child sketches an obstacle course, builds it from cushions and chairs, and writes the rules. Designing something for other people is early leadership."},{"t":"Coach for a Day","d":"Let them lead the family through a five-move warm-up they invent, correcting everyone's form like a real coach. Teaching a skill is the surest way to lock it in."}]},{"day":"Tuesday","focus":"Fitness by Numbers","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Perfect Ten Circuit","d":"Build a circuit of ten stations, ten reps each — jumps, hops, toe touches — and tally the grand total at the end. One hundred moves sounds impossible until it's done."},{"t":"Beat Your Best","d":"Time a sprint, count hops in one minute, then record and re-test all week on a simple chart. Graphing personal bests shows kids that practice literally adds up."}]},{"day":"Wednesday","focus":"Move and Feel","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Feelings in Motion","d":"After big movement, have your child journal how their body and mood changed — before, during, after. Mrs. Bear's Your Feelings Matter makes a lovely companion read together this week."},{"t":"Slow-Motion Reset","d":"Build a personal calm-down set — five slow stretches with deep breaths — and let your child name each pose. A toolkit they invented beats being told to calm down."}]},{"day":"Thursday","focus":"Games of the World","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Global Game Night","d":"Look up a children's game played in another country and try a backyard version together. Talk about how kids everywhere invent play from whatever they have."},{"t":"Invent-a-Sport","d":"Challenge your child to invent a brand-new sport with a name, a logo, and three fair rules, then demonstrate it. Writing original rules takes real creative reasoning."}]},{"day":"Friday","focus":"Family Field Day","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Heartbeat Lab","d":"Find a pulse at rest, then after thirty jumping jacks, counting beats for ten seconds each time. Ask why the heart speeds up — that's exercise science in your own wrist."},{"t":"Field Day Finale","d":"Let your child run the family field day they designed — stations, scorekeeping, and a closing speech thanking every athlete. Leading it start to finish is the month's real trophy."}]}],"homeden":{"title":"The Home Den — This Week","lead":"The finale week — your child is the coach, and you are the team.","items":["Say yes to being coached — kids lead better when the grown-ups play along.","Post the week's personal bests on the fridge and cheer every new record.","Have your big kid read a Bear Phonics reader aloud to a younger sibling — teaching is the deepest practice.","Wind down each night with ten slow stretches and one favorite chapter before bed."]}}]},"jun":{"theme":"Sun, Sand & Splash","weeks":[{"label":"Week 1 — At the Beach","days":[{"day":"Monday","focus":"Sink or Float","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Prediction Splash Lab","d":"Gather ten household objects, have your child predict sink or float in a basin, then test and score their guesses — water play within arm's reach. The wrong guesses are the interesting ones."},{"t":"Make It Float","d":"Challenge them to rescue one sinker using foil, corks, or a plastic-lid raft until it stays on the surface. Saving a sinking object is engineering with a mission."}]},{"day":"Tuesday","focus":"Water by Numbers","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Scoop and Estimate","d":"Line up containers and estimate, then measure, how many quarter-cups each one holds — does anything hold exactly eleven, this month's number? Estimating before measuring is the mathematician's habit."},{"t":"Drip Race Timer","d":"Poke same-size holes in two cups, fill them over the basin, and time which empties first — then change the hole size and retest. Flow rate is real physics you can time."}]},{"day":"Wednesday","focus":"Beach Words and Art","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Seaside Story Starter","d":"Read a beach or ocean book together, then have your child write the next chapter — what washes ashore the following morning? Continuing a story is the fun way into writing."},{"t":"Aqua Palette Studio","d":"Mix paints or layer crayon shades to invent five versions of aqua — this month's color — and name each one like a paint company would. Naming shades builds precise describing words."}]},{"day":"Thursday","focus":"Safe and Strong","domains":["Physical Development","Social Studies"],"opts":[{"t":"Water-Safety Captain","d":"Have your child design a water-safety poster with the family rules — always within arm's reach, buddy system, sunscreen — and present it before any splash time. Teaching the rules is how kids own them."},{"t":"Beach Towel Bootcamp","d":"Lay towels across the yard as islands and lead hop, swim-arms, and crawl moves between them. Big summer movement works best in morning shade with water breaks."}]},{"day":"Friday","focus":"Beach Builders","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Sandcastle Blueprint","d":"At a sandbox, beach, or with salt dough at the table, have your child sketch a castle first — counting its triangles, rectangles, and cylinders — then build to their own plan. Following your own blueprint builds follow-through."},{"t":"Compliment Wave","d":"End the week with each family member naming one thing someone else built, wrote, or bravely tried. Being seen for effort is the fuel for next week's try."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Water, cups, and big questions — this week's den is basically a splash zone.","items":["Keep all water play in a basin or sink, always within arm's reach.","Ask at bath time: why do you float better when you spread out?","Start a float-lab bin: corks, lids, foil, and anything waterproof.","Ten minutes of reading daily — ocean books earn bonus points this month."]}},{"label":"Week 2 — In the Water","days":[{"day":"Monday","focus":"Ocean Researcher","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Ocean Expert Project","d":"Let your child pick one ocean animal and become the family expert: read up on it, gather five solid facts, and start a research page. Choosing your own topic is what makes research stick."},{"t":"Ocean A to Z","d":"Kick off with an A-to-Z ocean word list — one sea word per letter, as far as they can get — then research their chosen animal to fill in the gaps. Alphabet review disguised as a deep dive."}]},{"day":"Tuesday","focus":"Deep-Sea Data","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Size It Up","d":"Look up the real length of their ocean animal, then measure it out in sidewalk chalk or string down the hallway. A whale measured in hallway-lengths is math nobody forgets."},{"t":"Depth Chart Builder","d":"Draw an ocean-depth chart from the sunlight zone down to the trench and place sea creatures where they truly live. Ordering depths is number-line thinking turned on its side."}]},{"day":"Wednesday","focus":"Habitat Studio","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Shoebox Reef","d":"Build a shoebox habitat — paper coral, cotton-ball anemones, a jellyfish on a string — accurate to where their animal really lives. Accuracy is what turns a craft into science."},{"t":"Master of Disguise","d":"Design a paper fish camouflaged for one exact spot in your house, tape up several, and see who can find them. Ask why the hiding works — that's adaptation."}]},{"day":"Thursday","focus":"Ocean Guardians","domains":["Social Studies","Physical Development"],"opts":[{"t":"Cleanup Crew Walk","d":"Take a brisk family walk with gloves and a bag, collecting litter before rain can carry it toward storm drains and waterways. Kids protect what they feel responsible for."},{"t":"Plastic-Free Audit","d":"Have your child count the single-use plastics in one room, then lead the family in choosing two easy swaps. Small audits grow real-world changemakers."}]},{"day":"Friday","focus":"Deep Dive Debrief","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Ocean Expert Presentation","d":"Have your child present their animal research to the family — facts, drawings, and one question they still wonder about. Applaud the wondering, not just the knowing."},{"t":"Read Under the Waves","d":"Drape a blanket over two chairs, add a flashlight, and read ocean books together inside your underwater cave. Cozy reading spots make lifelong readers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week your child becomes the family's ocean expert — dive in beside them.","items":["Ask about their ocean animal at dinner and let them do the teaching.","Watch a short ocean documentary clip together and each share one wow.","Bring a bag on walks — every piece of litter caught helps a waterway.","Library trip idea: one ocean book plus one anything-they-want book."]}},{"label":"Week 3 — Sun & Sky","days":[{"day":"Monday","focus":"Shadow Trackers","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Shadow Clock","d":"Trace your child's shadow — or a stick's — on the driveway at three different times in one day and measure each length. Ask why it moved; the answer is planetary."},{"t":"Noon Shadow Experiment","d":"Have them predict what time shadows will be shortest, then check on the hour and record the results. Predict, test, revise — the scientific method in sunlight."}]},{"day":"Tuesday","focus":"Sun Studio","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Sun-Fade Art Lab","d":"Arrange paper shapes on dark construction paper in a sunny window and leave them for several days. Peeking early is allowed — patience is the actual experiment."},{"t":"Sky Color Study","d":"Have your child paint or color the sky at two different times of day and compare the palettes side by side. Noticing changing light is an artist's superpower."}]},{"day":"Wednesday","focus":"Sun-Smart Squad","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Sunscreen PSA","d":"Have your child write and perform a thirty-second sun-safety announcement — hat, sunscreen, shade, water — for the whole family. Persuading an audience is literacy with a mission."},{"t":"Shade Map Survey","d":"Map your yard or park, marking the shady spots by time of day, and post it as the family's official summer guide. A useful map is community service in miniature."}]},{"day":"Thursday","focus":"Heat and Motion","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Shadow Tag Remix","d":"Play shadow tag in the morning cool — step on a shadow to tag it — then ask how the game would change at noon. Physics hides inside recess games."},{"t":"Evaporation Sprint","d":"Paint water lines on warm pavement with a brush and race to hop the whole line before it disappears. Where did the water go? Straight up into the air."}]},{"day":"Friday","focus":"Bright Ideas","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Gratitude Sun Rays","d":"Cut a big paper sun with eleven rays — this month's number — and write one thing the family is grateful for on each. Reading them aloud together is the warm part."},{"t":"Starlight Story Camp","d":"After sunset, spread a blanket outside or build a dark den inside, read together by flashlight, then connect stars into shapes — triangles, squares, pentagons. Shape review beats a worksheet under a real sky."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sunshine science all week — hats on, water bottles full.","items":["Morning and evening are the golden hours for summer experiments — skip the midday heat.","Reapply sunscreen together and make your child the official timer-keeper.","Ask on a walk: where does a puddle go when it disappears?","Keep the flashlight by the bookshelf — blanket-fort reading is a summer tradition."]}},{"label":"Week 4 — Summer Play","days":[{"day":"Monday","focus":"Camp Director","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Backyard Camp Blueprint","d":"Announce that your child is directing a one-day backyard camp this week: they plan the schedule, name the camp, and assign every family member a role. Planning for others is leadership homework."},{"t":"Camp Rules Council","d":"Hold a family meeting where your child proposes three fair camp rules and everyone gets a vote. Fair rules and real votes are citizenship at kid scale."}]},{"day":"Tuesday","focus":"Game Leader","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Teach-a-Game Tryout","d":"Have your child teach the family one active game — borrowed or invented — explaining the rules first, then adjusting when questions come. Great leaders revise on the fly."},{"t":"Cheer Squad Challenge","d":"Practice good sportsmanship on purpose: after every round, winners give a compliment and losers give a congratulations. Naming it out loud is what makes it a habit."}]},{"day":"Wednesday","focus":"Tournament Math","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Scoreboard Designer","d":"Have your child build a real scoreboard for tomorrow's games — brackets, tally columns, team names in bold camp colors. Brackets are secretly beautiful math."},{"t":"Eleven-Point Match","d":"Invent a target-toss game where the first to exactly eleven points wins — overshoot and you drop back to seven. Adding and subtracting under pressure is the fun kind of math."}]},{"day":"Thursday","focus":"Camp Reporter","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Camp Newsletter Desk","d":"Have your child write and illustrate a one-page camp newsletter — headline, game results, weather report, tomorrow's schedule. Writing for a real audience makes every word matter."},{"t":"Bubble Solution Lab","d":"Mix three homemade bubble solutions, changing one ingredient at a time, and test which makes the longest-lasting bubbles for closing day. Changing one variable is real chemistry."}]},{"day":"Friday","focus":"Closing Ceremony","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Camp Awards Night","d":"Have your child create a handmade award for every family member — silliest splash, kindest camper — and host the ceremony. Noticing what others did well is a leadership superpower."},{"t":"Campfire Story Circle","d":"Gather in a blanket-fort campfire — flashlight glow, no flames — and take turns telling one tale and reading one book aloud together. The oldest camp tradition is a story."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Camp week — your child runs the show, you pack the enthusiasm.","items":["Follow your camper-in-chief's schedule — being led is the gift this week.","Water breaks and shade breaks between every game, no exceptions.","Snap photos of the scoreboard and newsletter for the summer scrapbook.","Ask at bedtime: what would you change if camp ran again tomorrow?"]}}]},"jul":{"theme":"Imagination Station","weeks":[{"label":"Week 1 — Once Upon a Time","days":[{"day":"Monday","focus":"Story Spark","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Original Story Draft","d":"Give the classic launch — what if? — and have your child draft an original story with a hero, a problem, and a fix. First drafts are allowed to be messy; that's what drafts are for."},{"t":"Purple Door Prompt","d":"Tape a paper purple door to the wall — this month's color — and ask what's behind it. Have them write or record the answer as a story opening. One strange door can unlock a whole world."}]},{"day":"Tuesday","focus":"Plot Builders","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Story Cube Roll","d":"Fold a paper cube — a sneaky shape review — and draw a character, place, or object on each of its six faces. Roll it three times and weave the results into one tale."},{"t":"Plot Mountain Map","d":"Chart their story on a plot mountain: the setup climbs, the problem peaks, the ending slides down. Seeing a story's shape makes revising it far less mysterious."}]},{"day":"Wednesday","focus":"Story Keepers","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Family Story Interview","d":"Have your child call the oldest relative they can reach and ask: what was your favorite story as a kid? Retell it at dinner. Every family is a library."},{"t":"Tales Around the World","d":"Read a folktale from another country together and talk about what its hero feels, fears, and learns. Old stories carry big feelings across centuries."}]},{"day":"Thursday","focus":"Stagecraft Lab","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Shadow Puppet Theater","d":"Cut card puppets, hang a sheet, and aim a flashlight from behind to stage a scene. Move a puppet closer to the light and watch it grow — that's optics on stage."},{"t":"Foley Sound Studio","d":"Recreate story sounds with household objects — rice rain in a jar, coconut-cup hoofbeats, crinkle-bag campfire. Ask which materials make high sounds and which make low ones."}]},{"day":"Friday","focus":"Premiere Night","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Story Premiere","d":"Host the big performance: your child presents their original story — read aloud, acted, or puppet-staged — with paper tickets and a front-row audience. Finishing what you started deserves a spotlight."},{"t":"Author Interview","d":"After the show, interview the author: what was hard, what changed along the way, what happens next? Reflecting like a real writer builds the courage to write again."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Story week — every ordinary evening is raw material.","items":["Ask what if in the car and let the story run wild.","Keep a story notebook by the bed for lightning-strike ideas.","Trade roles at bedtime: your child reads a page, you read a page.","Applaud drafts, not just finales — messy middles are where writers grow."]}},{"label":"Week 2 — Make-Believe & Dress-Up","days":[{"day":"Monday","focus":"Inventor's Notebook","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Problem Safari","d":"Walk the house together listing five small everyday problems — tangled cords, vanishing socks — then pick one worth solving. Inventors are just people who notice."},{"t":"Twelve-Idea Sprint","d":"Set a timer and have them sketch twelve invention ideas — this month's number — before it rings, brilliant or ridiculous, no judging allowed. Quantity first is how designers find quality."}]},{"day":"Tuesday","focus":"Prototype Studio","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Cardboard Prototype Build","d":"Build a working model of the chosen invention from boxes, tape, and string, measuring the parts so they actually fit together. Measure twice, tape once."},{"t":"Test and Tweak","d":"Run three trials of the prototype, score each out of ten, and make one improvement between rounds. Version two is always smarter than version one."}]},{"day":"Wednesday","focus":"Inventors and Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Young Inventor Story","d":"Read together about a real inventor — especially one who started young — and list what failed before what finally worked. History is full of glorious flops."},{"t":"Persuasive Product Ad","d":"Have your child write a catchy ad for their invention: a name, a slogan, and three reasons the world needs it. Persuasion is writing with a job to do."}]},{"day":"Thursday","focus":"Character Builders","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Hero Training Camp","d":"Have your child invent a character — closet costume, backstory, one special skill — then design a training course to master that skill. Practicing being someone brave is practice at being brave."},{"t":"Character Improv Duel","d":"Draw two invented characters from a hat and improvise a scene where they must solve a problem together. Improv builds flexible thinking and reading the room."}]},{"day":"Friday","focus":"Invention Convention","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Family Invention Expo","d":"Set up a display table where your child demos the prototype, the ad, and the design sketches for the family — questions welcome. Presenting your own idea is a courage rep."},{"t":"Purple Ribbon Judging","d":"Flip the script: family members each pitch a silly invention while your child judges, awarding purple ribbons for creativity, effort, and originality. Giving thoughtful feedback is a skill too."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Invention week — the recycling bin is the supply store.","items":["Stock a maker box: boxes, tape, string, lids, and rubber bands.","Ask how would you fix that whenever something small goes wrong.","Celebrate flops out loud — every good inventor collects them.","Read a how-things-work page together before bed."]}},{"label":"Week 3 — Art & Music","days":[{"day":"Monday","focus":"Mural Director","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Big Wall Mural","d":"Tape a long paper banner to a wall and let your child direct a family mural — they choose the theme, sketch the plan, and assign each person a section. Directing means guiding, not doing it all."},{"t":"Hallway Gallery Curator","d":"Have your child curate a hallway gallery of family art, complete with title cards and an order that tells a story. Curating is an art form of its own."}]},{"day":"Tuesday","focus":"Sound Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Water Glass Xylophone","d":"Fill glasses to different levels, tap gently with a spoon, and arrange them from lowest note to highest. Ask why less water makes a higher sound — vibration is the answer."},{"t":"Rhythm Code Composer","d":"Invent a rhythm from long and short claps, write it down as dashes and dots, and see if the family can decode and play it back. Rhythm notation is math you can dance to."}]},{"day":"Wednesday","focus":"Art of the World","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Artists of the World","d":"Read together about artists from three different countries — library books or a museum website — and have your child choose a favorite work and defend the choice. Taste plus reasons equals art criticism."},{"t":"Artist Statement","d":"Have your child write a short artist statement for one of their own pieces: what it shows, how they made it, and what it means. Naming your choices is thinking made visible."}]},{"day":"Thursday","focus":"Move to Music","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Dance Choreographer","d":"Have your child choreograph an eight-count dance to a favorite song and teach it to the family move by move. Counting beats while moving is coordination gold."},{"t":"Conductor's Baton","d":"Hand them a wooden-spoon baton to conduct the family kitchen band — louder, softer, faster, freeze. A good conductor leads without saying a word."}]},{"day":"Friday","focus":"Opening Night","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Arts Showcase Night","d":"Host the week's finale: mural unveiling, dance premiere, kitchen-band concert — your child is director and emcee. Take a bow; running a show is big work."},{"t":"Talk-Back Session","d":"After the show, hold a theater-style talk-back where the audience asks the director questions and names specific favorite moments. Specific praise teaches artists exactly what worked."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Arts week — the fridge gallery is about to get competitive.","items":["Say yes to the mess; lay an old sheet under the big projects.","Let your child DJ one dinner cleanup with a favorite song.","Play A-to-Z categories on drives: instruments, artists, or colors, letter by letter.","Read one picture-book artist biography together this week."]}},{"label":"Week 4 — Dream Big","days":[{"day":"Monday","focus":"Vision Board","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Dream Vision Board","d":"Have your child build a vision board — drawings, magazine cutouts, big bold words — showing what they want to create, learn, and become. Post it where they'll see it every day."},{"t":"Purple Sky Portrait","d":"Have them draw a self-portrait ten years from now under a big purple sky, doing the thing they dream of doing. Seeing it on paper makes it feel possible."}]},{"day":"Tuesday","focus":"Goal Getters","domains":["Approaches to Learning","Mathematical Thinking"],"opts":[{"t":"Twelve-Stop Trail Map","d":"Pick one dream from the board and map it as a hiking trail with twelve stops — this month's number — from trailhead today to the summit. Circle the first stop reachable this week. Long trails get walked one stop at a time."},{"t":"Summer Countdown Math","d":"Count the days left of summer, then calculate how many practice sessions fit if they work at their goal three times a week. Real plans use real numbers."}]},{"day":"Wednesday","focus":"Future Voices","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Letter to Future Me","d":"Have your child write a letter to themselves one year from now — hopes, predictions, one piece of advice — and seal it with an opening date. Future readers are great motivators."},{"t":"Dream Job Interview","d":"Help them find someone with a job they admire — a relative, neighbor, or coach — and ask three prepared questions. Real people make dreams concrete."}]},{"day":"Thursday","focus":"Try It Day","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"New Skill Bootcamp","d":"Let your child attempt one physical skill from the vision board — juggling, a cartwheel, a jump-rope trick — with ten focused minutes of practice. Day one is supposed to be wobbly."},{"t":"Practice Data Lab","d":"Track attempts and successes across three short practice rounds and graph the change. Watching your own learning curve is proof that practice works."}]},{"day":"Friday","focus":"Dream Celebration","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Family Dream Share","d":"Host a dream-share night where everyone — grown-ups included — presents one dream and the first step they'll take toward it. Dreams said out loud gather helpers."},{"t":"Storybook Send-Off","d":"Close the month by reading together a book about a determined dreamer, and talk about the moment the character almost quit. Almost-quitting is part of every big dream."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Dream-big week — the whole family is invited to the vision party.","items":["Hang the vision board somewhere the whole family passes daily.","Share one of your own childhood dreams at dinner — kids love the plot twist.","Cheer the first wobbly attempts louder than the easy wins.","Mark a calendar date to open the letter to future me together."]}}]}};